window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c36-plumbing"] = window.COURSE_LANG["c36-plumbing"] || {};
window.COURSE_LANG["c36-plumbing"]["ru"] = [
  {id:1, q:"У какой медной водопроводной трубы самая толстая стенка, и её предпочитают для подземного ввода воды?", opts:["Тип M","Тип L","Тип K","Тип DWV"], re:"У типа K самая толстая стенка среди обычных водопроводных труб, поэтому его применяют под землёй и там, где нужны высокое давление или механическая защита."},
  {id:2, q:"Какая пластиковая труба сертифицирована для распределения горячей и холодной воды внутри здания?", opts:["PVC","CPVC","ABS","Чугун"], re:"CPVC — это хлорированный PVC, рассчитанный на горячую воду; обычный PVC для распределения горячей воды не сертифицирован."},
  {id:3, q:"Чёрная труба ABS в здании чаще всего используется для:", opts:["Канализации, стоков и вентиляции (DWV)","Горячей воды под давлением","Подачи природного газа","Питьевой холодной воды под давлением"], re:"ABS — чёрный термопласт, широко применяемый для системы DWV (канализация, стоки и вентиляция), а не для воды под давлением."},
  {id:4, q:"Медную трубу типа L чаще всего применяют для:", opts:["Внутренних линий водоснабжения в жилых домах","Только подземных линий противопожарного водопровода","Только труб канализации и вентиляции","Только труб топливного газа"], re:"У типа L средняя толщина стенки, и это самая распространённая медная труба для внутреннего распределения воды."},
  {id:5, q:"По сравнению с типами K и L, медная труба типа M имеет:", opts:["Стенку толще, чем у K","Стенку, идентичную K","Самую тонкую стенку из трёх","Никакого применения для водоснабжения"], re:"У типа M самая тонкая стенка из трёх; некоторые юрисдикции ограничивают, где тип M можно применять для воды."},
  {id:6, q:"Оцинкованная стальная труба для воды вышла из употребления, потому что со временем она:", opts:["Не поддаётся нарезке резьбы","Не может проводить холодную воду","Слишком гибкая для крепления","Корродирует изнутри и ограничивает поток"], re:"Внутреннее цинковое покрытие со временем стирается, и сталь ржавеет, сужая просвет, ограничивая поток и вызывая течи."},
  {id:7, q:"Трубу PEX лучше всего описать как:", opts:["Жёсткую металлическую трубу","Глиняное дренажное изделие","Гибкую трубку из сшитого полиэтилена","Жёсткий стеклопластиковый кожух"], re:"PEX — это сшитый полиэтилен, гибкая пластиковая трубка для распределения горячей и холодной воды, соединяемая механическими фитингами."},
  {id:8, q:"Чугунную трубу без раструба (no-hub) применяют главным образом для:", opts:["Питьевой воды под давлением","Распределения топливного газа","Линий сжатого воздуха","Санитарной канализации, стоков и вентиляции (DWV)"], re:"Чугун no-hub — самотёчный материал DWV, ценимый за прочность и бесшумность, а не для службы под давлением."},
  {id:9, q:"Какой материал НЕ одобрен для распределения питьевой горячей воды?", opts:["Медь типа L","CPVC","Обычный PVC","PEX"], re:"Обычный PVC рассчитан только на холодную воду и DWV; медь, CPVC и PEX сертифицированы для горячей воды."},
  {id:10, q:"Ключевое преимущество чугунной канализационной трубы перед пластиковой DWV в том, что она:", opts:["Глушит шум текущей воды","Легче в обращении","Стоит дешевле","Никогда не требует опор"], re:"Масса чугуна приглушает шум воды, движущейся по трубе, что является преимуществом в жилых зданиях."},
  {id:11, q:"Латунные трубы и фитинги в сантехнике — это сплав главным образом из:", opts:["Железа и углерода","Свинца и сурьмы","Алюминия и олова","Меди и цинка"], re:"Латунь — это в основном медь и цинк; латунь для питьевой воды также должна отвечать требованиям по отсутствию свинца."},
  {id:12, q:"Для подземного ввода воды в здание монтажник скорее всего выберет:", opts:["Медь типа M или тонкостенную трубу","Трубу ABS для DWV","Медь типа K или другую одобренную трубу с напорным рейтингом","PVC с ячеистым сердечником"], re:"Подземному вводу нужен тяжёлый, прочный материал с напорным рейтингом, например медь типа K или другая одобренная труба для водоснабжения."},
  {id:13, q:"Труба PVC пригодна для:", opts:["Холодной воды и применений DWV","Распределения горячей воды при 180 F","Труб топливного газа","Линий пара"], re:"PVC рассчитан на холодную воду и канализацию; он размягчается при температурах горячей воды и не применяется для горячего снабжения, газа или пара."},
  {id:14, q:"Какую трубу обычно прокладывают длинными непрерывными бухтами, чтобы уменьшить число фитингов внутри стен?", opts:["Чугун","Жёсткую медь","PEX","Оцинкованную сталь"], re:"Гибкий PEX можно прокладывать длинными бухтами от коллектора к каждому прибору, уменьшая скрытые фитинги и возможные точки течи."},
  {id:15, q:"Мягкая (отожжённая) медная труба отличается от твёрдотянутой меди тем, что она:", opts:["Всегда имеет более тонкую стенку","Применяется только для газа","Не поддаётся пайке","Гнётся руками и продаётся в бухтах"], re:"Мягкая медь отожжена, чтобы её можно было гнуть и сворачивать в бухты; твёрдотянутая медь жёсткая и поставляется в прямых отрезках."},
  {id:16, q:"Что из перечисленного является термопластичной трубой DWV, а не металлом?", opts:["Чугун no-hub","Оцинкованная сталь","ABS","Красная латунь"], re:"ABS (акрилонитрилбутадиенстирол) — чёрная пластиковая труба DWV; остальное — металлы."},
  {id:17, q:"Частая причина выбрать медь вместо пластика для водопровода в том, что медь:", opts:["Выдерживает более высокие температуры, жёсткая и долговечная","Невосприимчива ко всякой коррозии","Всегда дешевле","Не требует фитингов"], re:"Медь выдерживает высокие температуры, жёсткая и долговечная, широко принята, хотя стоит дороже пластика."},
  {id:18, q:"«Сверхтяжёлый» и «сервисный вес» — это классы толщины стенки, связанные с:", opts:["Трубой PEX","Мягкой медью","Трубой CPVC","Чугунной канализационной трубой"], re:"Раструбную чугунную канализационную трубу делают в классах сервисного веса и сверхтяжёлом, отличающихся толщиной стенки."},
  {id:19, q:"Какое утверждение о трубах DWV из ABS и PVC верно?", opts:["Обе металлические","Обе рассчитаны на горячее водоснабжение","ABS обычно чёрная, а PVC обычно белая","Ни одну нельзя применять для канализации"], re:"Труба DWV из ABS обычно чёрная, а из PVC обычно белая; обе — пластиковые дренажные материалы, не напорные."},
  {id:20, q:"Напорный рейтинг материала трубы, как правило, снижается, когда:", opts:["Её стенка становится тоньше","Её стенка становится толще","Её длина увеличивается","Её цвет меняется"], re:"При заданном диаметре и материале более тонкая стенка несёт меньшее давление, поэтому медь типа M имеет рейтинг ниже типа K."},
  {id:21, q:"Жёсткие трубы PVC и CPVC обычно соединяют с помощью:", opts:["Пайки с флюсом","Хомутов no-hub","Обжимных колец","Клея-растворителя (с праймером на PVC/CPVC)"], re:"PVC и CPVC химически сваривают клеем-растворителем; растворитель размягчает и сплавляет поверхности в единое целое."},
  {id:22, q:"Медную водопроводную трубу и фитинги чаще всего соединяют:", opts:["Сваркой растворителем","Нарезкой резьбы на мягкой меди","Пайкой мягким припоем (sweating)","Холодным обжимом лентой"], re:"Медные стыки обычно паяют (sweating) с флюсом и бессвинцовым припоем, втягивая расплавленный припой в раструб капиллярными силами."},
  {id:23, q:"Трубу PEX для воды обычно соединяют, используя:", opts:["Клей-растворитель","Свинцово-канатные стыки","Пайку твёрдым припоем (brazing)","Обжимные, расширительные или вставные фитинги"], re:"PEX гибкий и соединяется механически обжимными кольцами, расширительными или вставными фитингами, а не клеем или припоем."},
  {id:24, q:"Назначение праймера, наносимого перед клеем-растворителем PVC:", opts:["Лишь окрасить стык для осмотра","Размягчить и очистить поверхность, чтобы клей мог её сплавить","Смазать трубу для сборки","Ускорить отверждение клея после сборки"], re:"Праймер размягчает и подготавливает поверхность PVC/CPVC и удаляет загрязнения, чтобы клей-растворитель мог правильно сплавить стык."},
  {id:25, q:"Чугунную трубу без раструба (no-hub) соединяют с помощью:", opts:["Неопреновой манжеты внутри экранированного хомута из нержавеющей стали","Расплавленного свинца и каната","Клея-растворителя","Развальцованной латунной гайки"], re:"Стыки no-hub используют эластомерную (неопреновую) манжету в гофрированном экране из нержавеющей стали с хомутами, затянутыми до заданного момента."},
  {id:26, q:"Прессовый (press-fit) стык на меди выполняют:", opts:["Нагревом фитинга горелкой","Обжимом фитинга с внутренним O-кольцом на трубе прессовым инструментом","Нарезкой резьбы трубы в фитинг","Склейкой трубы клеем-растворителем"], re:"Прессовые фитинги содержат O-кольцо; прессовый инструмент обжимает фитинг на трубе, образуя герметичное механическое уплотнение без пламени."},
  {id:27, q:"Ключевое преимущество безопасности прессовых фитингов перед пайкой в том, что они:", opts:["Требуют открытого пламени","Не нуждаются в пламени, флюсе или припое","Делаются только на сухой трубе","Не поддаются осмотру"], re:"Прессовые стыки выполняются холодным инструментом, что исключает открытое пламя и риск огневых работ, присущий пайке."},
  {id:28, q:"Развальцованный стык на мягкой меди выполняют:", opts:["Развальцовкой конца трубы в конус 45 градусов, удерживаемый накидной гайкой","Заливкой припоя в раструб","Склейкой трубы в гнездо","Обжимом кольца поверх ёлочки"], re:"Конец мягкой медной трубы развальцовывают в конус 45 градусов и прижимают к седлу гайкой — метод применяют для топливного газа и подобных соединений."},
  {id:29, q:"При соединении двух разных дренажных пластиков, например ABS и PVC, рекомендуется:", opts:["Обмотать стык лентой","Нагреть оба конца и сжать","Нарезать резьбу пластика в пластик","Применить одобренную переходную муфту или переходный клей"], re:"Разные пластики следует соединять одобренной переходной муфтой (или сертифицированным переходным клеем), а не смешивать их отдельные клеи."},
  {id:30, q:"Свинцово-канатные (зачеканенные) стыки связаны с:", opts:["Трубой PEX","Газовыми линиями из мягкой меди","Трубой CPVC","Раструбной чугунной канализационной трубой"], re:"Традиционный раструбный чугунный стык заполняют канатом в раструбе, а затем заливают расплавленным свинцом; стыки с манжетами в основном вытеснили его."},
  {id:31, q:"Флюс для пайки наносят на медный стык главным образом, чтобы:", opts:["Повысить давление воды","Очистить металл и помочь припою затечь в стык","Добавить цвет фитингу","Замедлить припой"], re:"Флюс удаляет оксиды и позволяет расплавленному припою смачивать и затекать в стык капиллярными силами для прочного уплотнения."},
  {id:32, q:"Резьбовые стыки стальной или латунной трубы уплотняют с помощью:", opts:["Клея-растворителя","Уплотнительной пасты или ленты ПТФЭ на резьбе","Неопреновой манжеты","Пресса с O-кольцом"], re:"Коническую резьбу (NPT) уплотняют пастой для резьбы (pipe dope) или лентой ПТФЭ, заполняющей спираль резьбы и предотвращающей течи."},
  {id:33, q:"Вставной (push-fit) фитинг удерживает трубу с помощью:", opts:["Клея-растворителя внутри гнезда","Внутренних захватных зубьев и уплотнения O-кольцом","Залитой свинцовой манжеты","Сварного валика"], re:"Вставные фитинги используют зубья из нержавеющей стали для удержания трубы и O-кольцо для уплотнения, позволяя соединение без инструмента на меди, CPVC или PEX."},
  {id:34, q:"Соединения PEX холодным расширением работают так:", opts:["Труба сплавляется с фитингом","Труба и кольцо расширяются, затем стягиваются обратно на фитинг","Труба склеивается в гнезде","Стык зачеканивается свинцом"], re:"При холодном расширении (например, PEX-A) трубу и расширительное кольцо растягивают, вставляют фитинг, и память материала стягивает их плотно вокруг него."},
  {id:35, q:"Почему клеевым стыкам PVC нужно дать правильное время схватывания и отверждения перед подачей давления?", opts:["Чтобы праймер высох до нужного цвета","Чтобы растворитель развил полную прочность стыка","Чтобы труба остыла после пайки","Чтобы резьба села"], re:"Сварке растворителем нужно время на схватывание и отверждение, чтобы сплавленное соединение набрало полную прочность до подачи давления; спешка может вызвать отказы."},
  {id:36, q:"В паяном медном стыке капиллярное действие означает:", opts:["Давление воды выталкивает припой наружу","Расплавленный припой втягивается в зазор между трубой и фитингом","Размер пламени горелки","Превращение флюса в золу"], re:"Правильно подобранный зазор стыка позволяет капиллярным силам втянуть расплавленный припой по всему раструбу для полного уплотнения."},
  {id:37, q:"Какой метод соединения выполняют на мокрой или неосушённой медной линии, не сливая её сначала?", opts:["Пайка мягким припоем","Пайка твёрдым припоем (brazing)","Прессовый фитинг","Нарезка резьбы"], re:"Прессовые фитинги можно выполнять на линиях, которые не полностью осушены, в отличие от пайки, требующей сухой зоны стыка."},
  {id:38, q:"Хомуты из нержавеющей стали муфты no-hub затягивают до:", opts:["Только от руки без инструмента","Заданного момента калиброванным ключом","Полной деформации экрана","Никакого определённого значения"], re:"Хомуты затягивают до заданного производителем момента (обычно 60 дюйм-фунтов), чтобы манжета уплотнила без перетяжки или недотяжки."},
  {id:39, q:"Пайка твёрдым припоем (brazing) отличается от мягкой пайки тем, что brazing:", opts:["Использует присадку с более низкой температурой","Использует присадку с более высокой температурой для более прочных стыков","Не требует нагрева","Использует клей-растворитель"], re:"Brazing использует более высокие температуры и присадки, плавящиеся выше примерно 840 F, давая более прочные стыки, чем мягкая пайка."},
  {id:40, q:"Перед пайкой конец медной трубы и гнездо фитинга должны быть:", opts:["Покрыты краской","Очищены до блеска наждачной тканью или ёршиком для фитингов","Вымочены в праймере","Нагреты докрасна"], re:"Очистка сопрягаемых поверхностей до блестящего металла удаляет оксид, чтобы флюс и припой хорошо сцепились и стык не дал течь."},
  {id:41, q:"Разъёмное соединение (union) ставят на трубопроводе главным образом, чтобы:", opts:["Уменьшить диаметр трубы","Позволить разъединить трубу без резки","Изменить направление потока на 90 градусов","Выпустить запертый воздух"], re:"Разъёмное соединение позволяет разобрать и снова собрать участок трубы для обслуживания без резки, отвернув его центральное кольцо."},
  {id:42, q:"Диэлектрическое соединение применяют, чтобы:", opts:["Ускорить поток воды","Разделить разнородные металлы и предотвратить гальваническую коррозию","Снизить давление воды","Добавить прочистку"], re:"Диэлектрическое соединение электрически изолирует медь от стали или оцинковки, чтобы гальваническая коррозия не разъедала стык."},
  {id:43, q:"В трубопроводе DWV косой тройник (wye) предпочитают санитарному тройнику на горизонтальных участках, потому что он:", opts:["Дешевле в покупке","Вводит ответвление под углом около 45 градусов для плавного потока","Имеет большее отверстие","Не требует опоры"], re:"Косой тройник вводит ответвление под углом около 45 градусов, поддерживая движение стоков, чтобы твёрдые частицы не оседали, как это вызвал бы острый тройник на горизонтали."},
  {id:44, q:"Переходную муфту (редуктор) применяют, чтобы:", opts:["Соединить две трубы разного диаметра","Изменить направление потока","Закрыть конец линии","Добавить запорный кран"], re:"Переходная муфта соединяет более крупную трубу с более мелкой на прямом участке, обеспечивая переход между двумя размерами."},
  {id:45, q:"Отвод (колено, ell) применяют, чтобы:", opts:["Соединить три трубы","Изменить направление трубопровода","Снизить давление","Обеспечить прочистку"], re:"Отводы меняют направление трубы, обычно на 90 или 45 градусов; отводы длинного радиуса дают более плавный поворот для канализации."},
  {id:46, q:"Тройник (T) применяют, чтобы:", opts:["Закрыть линию","Создать ответвление от основного участка","Соединить две одинаковые трубы по прямой","Разобрать участок для обслуживания"], re:"Тройник даёт ответвление под 90 градусов к основному; санитарный тройник имеет скруглённый плавный переход для потока канализации."},
  {id:47, q:"Футорка (bushing) — это фитинг, применяемый, чтобы:", opts:["Переходить с большего отверстия фитинга на меньшую трубу","Изменить направление на 45 градусов","Соединить две трубы no-hub","Обеспечить отверстие сброса"], re:"Футорка вворачивается или вставляется в большее отверстие, уменьшая его до меньшего размера, занимая меньше места, чем переходная муфта."},
  {id:48, q:"Комбинацию косого тройника и отвода 1/8 применяют в канализации, чтобы:", opts:["Сделать острое ответвление 90 градусов на вертикальном стояке","Создать плавный поворот длинного радиуса для потока ответвления","Закрыть вентиляцию","Уменьшить сразу два размера"], re:"Сочетание косого тройника 45 градусов с отводом 1/8 образует длинный плавный поворот, позволяющий ответвлению войти, не перекрывая поток."},
  {id:49, q:"Муфту (прямую муфту) применяют, чтобы:", opts:["Соединить две трубы одного размера встык","Сделать ответвление линии","Изменить направление","Снизить давление"], re:"Прямая муфта соединяет две трубы одного диаметра по линии; скользящую или ремонтную муфту можно надвинуть, чтобы отремонтировать вырезанный участок."},
  {id:50, q:"Какой фитинг постоянно закрывает конец резьбовой трубы?", opts:["Колпачок (cap)","Разъёмное соединение","Косой тройник","Муфта"], re:"Колпачок навинчивается снаружи на наружный конец трубы, закрывая его; пробка закрывает внутреннее резьбовое отверстие изнутри."},
  {id:51, q:"На горизонтальной канализации прочистку лучше всего устроить с помощью:", opts:["Санитарного тройника, положенного на спину","Косого тройника (или комбинированного), чтобы пруток шёл по направлению потока","Простого колена 90 градусов","Простой прямой муфты"], re:"Косой тройник позволяет прочистному прутку идти по направлению потока, поэтому нормы требуют косого тройника, а не санитарного, для горизонтальной прочистки."},
  {id:52, q:"Отвод длинного радиуса (длинного выноса) предпочитают в канализации, потому что он:", opts:["Поворачивает поток более плавно, поддерживая движение стоков","Экономит место по сравнению с коротким отводом","Требуется только для вентиляции","Уменьшает размер трубы"], re:"Отвод длинного радиуса имеет больший радиус, плавно поворачивающий стоки, снижая вероятность засоров по сравнению с отводом короткого радиуса."},
  {id:53, q:"Фитинг типа «street» (например, street-колено) имеет:", opts:["Два внутренних конца","Три отверстия","Один наружный и один внутренний конец","Встроенный кран"], re:"Фитинг street имеет один наружный (гладкий) и один внутренний (раструбный) конец, поэтому входит прямо в другой фитинг без короткого ниппеля."},
  {id:54, q:"Когда медную трубу нужно соединить с оцинкованной стальной, предпочтительным по нормам является:", opts:["Простая латунная муфта","Диэлектрическое разъёмное соединение или диэлектрический фитинг","Гнездо под клей-растворитель","Развальцованный стык"], re:"Диэлектрический фитинг разделяет разнородные металлы, предотвращая гальваническую коррозию, которая иначе разъела бы соединение меди со сталью."},
  {id:55, q:"Переходник сифона (trap adapter) применяют, чтобы:", opts:["Соединить тонкостенный трубный сифон прибора со сливной трубой","Снизить давление воды","Вентилировать стояк","Соединить два чугунных раструба"], re:"Переходник сифона обеспечивает переход от тонкостенного трубного сифона прибора к стандартной сливной трубе DWV через накидную гайку и шайбу."},
  {id:56, q:"Фланец унитаза (closet flange) служит, чтобы:", opts:["Регулировать давление в бачке","Закрепить унитаз и соединить его со сливом","Вентилировать ванную","Уменьшить размер слива"], re:"Фланец унитаза крепится к полу и сливной трубе, обеспечивая поверхность уплотнения и анкеровку болтов для унитаза."},
  {id:57, q:"Почему число фитингов в водопроводной линии следует держать разумным?", opts:["Фитинги лишь увеличивают стоимость","Каждый фитинг добавляет потери на трение и возможную точку течи","Фитинги снижают прочность трубы до нуля","Фитинги никогда не одобрены нормами"], re:"Каждый фитинг добавляет трение (потерю давления) и ещё один стык, который может потечь, поэтому трассы планируют с использованием только нужных фитингов."},
  {id:58, q:"Редуктор в горизонтальной сливной линии обычно ставят как эксцентрический, чтобы:", opts:["Держать верх ровным, чтобы твёрдые частицы не застаивались","Резко увеличить уклон","Добавить вентиляцию","Позволить нарезку резьбы"], re:"Эксцентрический редуктор держит одну сторону (лоток) на одной линии, чтобы горизонтальная канализация не образовала карман, где скапливались бы твёрдые частицы и вода."},
  {id:59, q:"Муфта no-hub отличается от резьбового разъёмного соединения тем, что она:", opts:["Электрически уплотняет разнородные металлы","Соединяет чугун без раструба зажимным хомутом с манжетой","Применяется только на PEX","Требует клея-растворителя"], re:"Муфта no-hub зажимает манжету на концах чугунной трубы без раструба, тогда как разъёмное соединение — это резьбовой разборный стык для металлической трубы."},
  {id:60, q:"Пробку (plug) применяют, чтобы:", opts:["Закрыть внутреннее резьбовое отверстие","Закрыть наружный конец трубы","Сделать ответвление линии под 45 градусов","Уменьшить два размера трубы"], re:"Пробка вворачивается во внутреннее резьбовое отверстие или фитинг, закрывая его, тогда как колпачок надевается на наружный конец."},
  {id:61, q:"Задвижка (gate valve) лучше всего подходит для службы, которая:", opts:["Часто дросселирует поток","Полностью открыта или полностью закрыта (изоляция)","Только предотвращает обратный поток","Снижает давление в системе"], re:"Задвижка поднимает клин из проходного сечения при открытии и предназначена для полного открытия/закрытия, а не для дросселирования, где она может вибрировать и эродировать."},
  {id:62, q:"Запорно-регулирующий вентиль (globe valve) предназначен главным образом для того, чтобы:", opts:["Дросселировать и регулировать поток","Обеспечить отсечку четвертью оборота","Предотвращать обратный поток","Сбрасывать избыточное давление"], re:"Вентиль направляет поток через седло по Z-образному пути, давая хорошее дросселирование ценой большего падения давления, чем у задвижки или шарового крана."},
  {id:63, q:"Шаровой кран приводится в действие:", opts:["Многими оборотами маховика","Четвертью оборота (90 градусов) рукоятки","Поплавком","Тепловым расширением"], re:"Шаровой кран использует шар с отверстием, открывающийся или закрывающийся четвертью оборота, давая быструю и надёжную отсечку с низким падением давления."},
  {id:64, q:"Обратный клапан (check valve) устанавливают, чтобы:", opts:["Дросселировать поток","Пропускать поток в одном направлении и предотвращать обратный","Снизить давление до 80 psi","Отфильтровывать мусор"], re:"Обратный клапан пропускает поток в одну сторону и закрывается против обратного, помогая предотвратить обратный поток и защищая оборудование, например насосы."},
  {id:65, q:"Редукционный клапан давления (PRV) на вводе воды применяют, чтобы:", opts:["Повысить низкое входное давление","Снизить высокое входное давление до безопасного значения","Предотвратить обратный поток","Слить систему"], re:"PRV автоматически снижает высокое уличное давление до меньшего значения (обычно 80 psi или менее), защищая трубопровод и приборы здания."},
  {id:66, q:"Угловой запорный кран (stop прибора) ставят, чтобы:", opts:["Отключить воду одному прибору для обслуживания","Снизить давление во всём доме","Предотвратить гидроудар повсюду","Вентилировать слив прибора"], re:"Угловой кран позволяет изолировать один прибор, например смеситель или унитаз, для ремонта без отключения воды во всём здании."},
  {id:67, q:"Почему задвижка — плохой выбор для дросселирования потока?", opts:["Она не может закрыться полностью","Частичное открытие вызывает вибрацию и эрозию седла","У неё нет рукоятки","Она подходит только к пластиковой трубе"], re:"Удерживаемый приоткрытым диск задвижки вибрирует в потоке, и седло эродирует, поэтому задвижки используют полностью открытыми или закрытыми."},
  {id:68, q:"Типовой бытовой угловой кран имеет выход:", opts:["Компрессионный 3/8 дюйма","Резьбовой 2 дюйма","Раструб 4 дюйма","Только под пайку 1 дюйм"], re:"Большинство угловых кранов приборов имеют компрессионный выход 3/8 дюйма, подключаемый к подводке смесителя или унитаза."},
  {id:69, q:"Поливочный кран (sillcock), питающий садовый шланг, должен быть оснащён:", opts:["Регулятором давления","Вторым обратным клапаном на счётчике","Вакуумным прерывателем для подключения шланга","Более крупной рукояткой"], re:"Вакуумный прерыватель для подключения шланга не даёт загрязнённой воде быть засосанной через шланг обратно в питьевой водопровод."},
  {id:70, q:"В поворотном обратном клапане (swing check) запорным элементом является:", opts:["Скользящий клин","Шарнирный диск, захлопывающийся против обратного потока","Вращающийся шар","Мембрана, поджатая только пружиной"], re:"У поворотного обратного клапана шарнирный диск открывается прямым потоком и захлопывается, когда поток разворачивается."},
  {id:71, q:"Главный запорный кран на вводе воды в здание существует главным образом, чтобы:", opts:["Снижать давление","Изолировать воду всего здания для ремонта или в аварии","Нагревать воду","Вентилировать систему"], re:"Полнопроходной главный кран позволяет отключить подачу всего здания для обслуживания или в аварии, например при разрыве трубы."},
  {id:72, q:"По сравнению с задвижкой шаровой кран, как правило, обеспечивает:", opts:["Более медленную работу","Более быструю отсечку и надёжное уплотнение после долгого простоя","Лучшее тонкое дросселирование","Отсутствие напорного рейтинга"], re:"Шаровые краны закрываются четвертью оборота и обычно надёжно уплотняют даже после простоя, поэтому их широко применяют для отсечки."},
  {id:73, q:"Когда редукционный клапан создаёт закрытую систему, в установке также нужен:", opts:["Второй счётчик","Расширительный бак","Более крупный слив","Никакого дополнительного устройства"], re:"За PRV (или обратным клапаном) вода не может расшириться обратно в магистраль, поэтому добавляют расширительный бак, чтобы поглотить рост давления от нагрева."},
  {id:74, q:"Гаситель гидроудара — это устройство, которое:", opts:["Повышает статическое давление","Смягчает толчок, когда быстрозакрывающийся кран останавливает поток","Фильтрует осадок","Предотвращает замерзание"], re:"Гаситель содержит воздушную камеру или поршень, поглощающий скачок, возникающий при резкой остановке воды быстрозакрывающимся краном, уменьшая стук труб."},
  {id:75, q:"У какого типа крана наименьшее падение давления в полностью открытом состоянии?", opts:["Запорно-регулирующий вентиль","Задвижка или полнопроходной шаровой кран","Угловой вентиль","Донный клапан"], re:"Полностью открытые задвижка или полнопроходной шаровой кран оставляют почти свободный проход, давая очень малое сопротивление по сравнению с Z-путём вентиля."},
  {id:76, q:"Предохранительный клапан в закрытой системе водоснабжения отличается от запорного крана тем, что он:", opts:["Управляется вручную","Открывается автоматически для сброса избыточного давления","Непрерывно дросселирует поток","Только останавливает обратный поток"], re:"Предохранительный клапан подпружинен и открывается сам, когда давление (или температура) превышает заданный предел, защищая систему от разрыва."},
  {id:77, q:"Донный клапан (foot valve) внизу всасывающей линии насоса — это разновидность:", opts:["Регулятора давления","Обратного клапана, удерживающего линию залитой","Задвижки","Запорно-регулирующего вентиля"], re:"Донный клапан — это обратный клапан с фильтром, удерживающий воду (залив) во всасывающей линии, чтобы насос не терял залив."},
  {id:78, q:"На смесителе подводящие краны горячей и холодной воды по обычаю располагают так, чтобы лицом к прибору:", opts:["Горячая слева, холодная справа","Обе справа","Горячая справа, холодная слева","Расположение не имеет значения"], re:"По давней традиции горячая слева, а холодная справа у прибора, что совпадает с ожиданиями пользователя."},
  {id:79, q:"Угловой кран с четвертью оборота обычно выполнен как:", opts:["Многооборотный вентиль","Кран шарового типа","Мембранный кран","Задвижка"], re:"Современные угловые краны с четвертью оборота используют небольшой шаровой кран, более быстрый и реже заклинивающий, чем старые многооборотные компрессионные."},
  {id:80, q:"Главная причина ставить отдельные запорные краны у каждого прибора в здании:", opts:["Повысить общее давление","Позволить обслуживать каждый прибор без отключения воды во всём здании","Устранить необходимость в главном кране","Уменьшить размер трубы"], re:"Краны приборов позволяют изолировать один смеситель, унитаз или прибор для ремонта, пока остальная часть здания сохраняет водоснабжение."},
  {id:81, q:"Горизонтальную трубу DWV из PVC и ABS Schedule 40 обычно требуется поддерживать с интервалом около:", opts:["4 футов","12 футов","20 футов","Опора не требуется"], re:"Пластиковая труба DWV провисает между опорами, поэтому нормы обычно требуют горизонтальной опоры примерно каждые 4 фута для любого диаметра."},
  {id:82, q:"Опора или хомут трубы должны быть из материала, который:", opts:["Всегда стальной независимо от трубы","Совместим с трубой во избежание коррозии","Как можно меньше","Хорошо проводит электричество"], re:"Опоры должны быть совместимы с трубой (например, не голая сталь прямо на меди), чтобы не возникла гальваническая или химическая реакция, разъедающая трубу."},
  {id:83, q:"Изоляция трубы на линии горячей воды служит главным образом, чтобы:", opts:["Повысить давление воды","Снизить потери тепла и сэкономить энергию","Добавить конструктивную опору","Предотвратить обратный поток"], re:"Изоляция трубы горячей воды снижает потери тепла, поэтому вода приходит горячее, и водонагреватель тратит меньше энергии."},
  {id:84, q:"Изоляция трубы холодной воды во влажной зоне главным образом помогает:", opts:["Повысить расход","Контролировать конденсацию (потение) на трубе","Поднять температуру воды","Повысить давление"], re:"Холодные поверхности трубы ниже точки росы потеют; изоляция с закрытыми ячейками и пароизоляцией не даёт влаге конденсироваться и капать."},
  {id:85, q:"Изоляцию трубы применяют в неотапливаемых зонах главным образом, чтобы:", opts:["Ускорить слив","Замедлить потерю тепла и снизить риск замерзания","Добавить цветовую маркировку","Заменить опоры трубы"], re:"Изоляция не гарантирует, что труба не замёрзнет, но замедляет потерю тепла и удлиняет время до того, как застоявшаяся вода замёрзнет и разорвёт трубу."},
  {id:86, q:"Там, где голая медная труба иначе легла бы на стальную опору, правильная практика:", opts:["Соединить их электрически","Изолировать медь от стали совместимым или покрытым хомутом","Спаять их вместе","Оставить медь без опоры"], re:"Отделение меди от опор из разнородного металла хомутом с пластиковым покрытием или совместимым с медью предотвращает гальваническую коррозию в точке контакта."},
  {id:87, q:"Горизонтальную чугунную трубу без раструба обычно поддерживают:", opts:["Только на концах здания","У каждого стыка или рядом с ним (и в пределах ограниченного шага)","Каждые 20 футов","Никогда, потому что она жёсткая"], re:"Тяжёлый чугун и его стыки с манжетами поддерживают у каждого раструба/стыка или рядом и в пределах ограниченного шага, чтобы стыки не нагружались."},
  {id:88, q:"По сравнению с жёсткой металлической трубой пластиковая труба обычно требует:", opts:["Большего шага опор","Меньшего шага опор, так как она более гибкая","Никакой опоры","Опоры только в вертикальном положении"], re:"Пластиковая труба более гибкая и сильнее провисает, поэтому требует меньшего шага опор, чем металлическая того же размера."},
  {id:89, q:"Вертикальный трубопровод в многоэтажном участке обычно поддерживают:", opts:["Только в самом верху","На каждом этаже или в пределах ограниченного вертикального интервала","Никогда","Только у основания"], re:"Вертикальную трубу поддерживают на уровнях этажей или в пределах интервала по нормам (обычно не более примерно 10 футов), чтобы её вес нёсся по участкам, а не весь внизу."},
  {id:90, q:"Гибкая труба PEX, проложенная горизонтально, обычно требует опоры:", opts:["С большим шагом, чем жёсткая медь","С меньшим шагом, чем жёсткая медь, так как она гибкая","Только у коллектора","Никогда"], re:"Поскольку PEX гибкий и легко провисает, его поддерживают с меньшим шагом, чем жёсткую медь (часто около 32 дюймов по горизонтали)."},
  {id:91, q:"Главная задача опоры трубы:", opts:["Снижать давление воды","Нести вес трубы и содержимого и сохранять правильный уклон","Предотвращать обратный поток","Изолировать трубу"], re:"Опоры держат трубу и её воду, чтобы она не провисала, сохраняя требуемый уклон сливной трубы и предотвращая нагрузку на стыки."},
  {id:92, q:"Эластомерная пена с закрытыми ячейками — популярная изоляция трубы, потому что она:", opts:["Хорошо проводит тепло","Сопротивляется влаге и работает на горячих и холодных линиях","Является конструктивной опорой","Подходит только к чугуну"], re:"Пена с закрытыми ячейками сопротивляется впитыванию воды, что делает её пригодной для холодных линий (контроль конденсата) и горячих (удержание тепла) одинаково."},
  {id:93, q:"Там, где пластиковая сливная труба проходит через металлическую стойку или хомут, монтажник должен:", opts:["Зажать её так, чтобы она вообще не двигалась","Предусмотреть расширение и защитить трубу от истирания","Спаять точку контакта","Убрать опору"], re:"Пластиковая труба расширяется и сжимается от температуры, поэтому опоры должны давать ей двигаться и защищать от трения о металлические кромки."},
  {id:94, q:"Достаточная опора горизонтальной сливной линии важна главным образом потому, что провисание может:", opts:["Повысить давление воды","Создать низкие места (провисы), где скапливаются стоки","Улучшить вентиляцию","Уменьшить размер трубы"], re:"Провисание образует провис, удерживающий воду и твёрдые частицы, что ведёт к засорам, поэтому сливы нужно поддерживать для сохранения непрерывного уклона."},
  {id:95, q:"Изоляция и горячих, и холодных труб в стене также может помочь:", opts:["Увеличить гидроудар","Снизить шум воды, текущей в трубах","Поднять статическое давление","Устранить необходимость в кранах"], re:"Помимо теплового эффекта изоляция трубы может приглушить звук текущей воды и снизить шум, передаваемый через конструкцию."},
  {id:96, q:"Тип медной водопроводной трубы определяют на объекте по цветной полосе; тип K маркируется:", opts:["Красным","Синим","Зелёным","Жёлтым"], re:"По стандартному цветовому коду тип K — зелёный, тип L — синий, а тип M — красный, нанесён вдоль трубы."},
  {id:97, q:"Какой цвет маркировки несёт медная труба типа L?", opts:["Синий","Зелёный","Красный","Чёрный"], re:"Тип L маркируется синим; тип K — зелёный, а тип M — красный по общепринятой системе маркировки медной трубы."},
  {id:98, q:"Все трубы, припой и фитинги системы питьевой воды должны быть:", opts:["Окрашены в синий","Размером не менее 2 дюймов","Только оцинкованными","Без свинца"], re:"Материалы в контакте с питьевой водой должны отвечать пределам по отсутствию свинца для защиты качества воды — требование, подкреплённое федеральным законом и законом Калифорнии."},
  {id:99, q:"Труба PEX, продаваемая в красном и синем цветах, использует эти цвета, чтобы:", opts:["Указать разные напорные рейтинги","Обозначить горячие и холодные линии для монтажника","Показать, какая для газа","Отметить более толстые стенки"], re:"Цвет PEX (красный для горячей, синий для холодной, белый для любой) служит только для опознавания; цвет не меняет напорный и температурный рейтинг трубы."},
  {id:100, q:"Неопреновая манжета, применяемая в чугунной муфте no-hub, должна соответствовать:", opts:["Норме чистоты припоя","Норме эластомера, например ASTM C564","Норме твёрдости (temper) меди","Норме клея-растворителя"], re:"Неопреновую манжету для стыков чугуна без раструба нормируют по ASTM C564, что обеспечивает её уплотнение и стойкость к материалам системы канализации."},
  {id:101, q:"Трубу ввода воды лучше всего определить как трубу, идущую от:", opts:["Городской магистрали или источника до системы распределения воды здания","Водомера до самого дальнего прибора","Водонагревателя до каждого прибора","От прибора к прибору внутри стены"], re:"Ввод воды — это труба между городской магистралью (или иным источником) и точкой, где начинается система распределения здания, обычно у самой конструкции или сразу за ней."},
  {id:102, q:"Полнопроходной кран, требуемый для водомера, должен иметь проходное сечение, которое:", opts:["Вдвое меньше сечения ввода","Не менее сечения ввода воды","Вдвое больше сечения ввода","Меньше ввода, чтобы дросселировать поток"], re:"Кран водомера должен быть полнопроходного типа, его открытая площадь должна быть не меньше сечения ввода, чтобы не ограничивать поток."},
  {id:103, q:"Минимальный слой грунта над заглублённой трубой ввода воды обычно требуется около:", opts:["3 дюймов","6 дюймов","12 дюймов","36 дюймов"], re:"Кодексы обычно требуют не менее 12 дюймов засыпки над верхом заглублённой трубы ввода, чтобы защитить её."},
  {id:104, q:"Когда канализационный выпуск здания не из одобренного напорного материала, труба ввода воды должна отстоять от него по горизонтали не менее чем на:", opts:["1 фут","2 фута","20 футов","5 футов"], re:"Ввод воды должен отстоять не менее чем на 5 футов ненарушенного или уплотнённого грунта от обычного канализационного выпуска, чтобы снизить риск загрязнения."},
  {id:105, q:"Ввод воды можно вести ближе 5 футов к канализационному выпуску только если труба воды уложена:", opts:["Не менее чем на 12 дюймов выше верха выпуска","Ниже выпуска","В одной траншее на том же уровне","Из чугуна"], re:"Зазор в 5 футов можно уменьшить, если низ трубы ввода воды не менее чем на 12 дюймов выше наивысшей точки выпуска."},
  {id:106, q:"Когда труба ввода воды должна пересекать канализационный выпуск здания, трубу воды следует:", opts:["Оставить голой и касающейся выпуска","Заключить в гильзу или держать её стыки подальше от пересечения","Уменьшить на один размер","Привязать к выпуску как опору"], re:"На пересечении ввод воды обычно заключают в гильзу или держат его стыки вдали от выпуска, чтобы при течи не засосало загрязнение."},
  {id:107, q:"Сливной (спускной) кран на стороне выхода крана внутреннего водомера ставят главным образом, чтобы:", opts:["Повысить давление","Нагреть водомер","Позволить слить трубопровод за ним","Стравить газ"], re:"Сливной кран за водомером позволяет опорожнить трубопровод здания для ремонта или защиты от замерзания."},
  {id:108, q:"Главный запорный (управляющий) кран здания обычно располагают:", opts:["У самого дальнего прибора","На крыше","Внутри водонагревателя","Рядом с местом ввода в здание или у водомера, в легкодоступном месте"], re:"Легкодоступный полнопроходной управляющий кран ставят рядом с водомером или у ввода, чтобы можно было отключить всё здание."},
  {id:109, q:"Водомер служит главным образом для того, чтобы:", opts:["Измерять объём использованной воды","Снижать давление воды","Предотвращать обратный поток","Фильтровать осадок"], re:"Водомер учитывает количество воды, поступающей в здание, для расчётов; это не устройство давления или защиты от обратного потока."},
  {id:110, q:"Сгоны (американки) на входе и выходе водомера ставят, чтобы водомер можно было:", opts:["Накачать большим давлением","Снять или заменить, не разрезая трубу","Использовать как запор","Закопать глубже"], re:"Сгоны позволяют снять и поставить водомер для обслуживания или замены без разрезания трубопровода."},
  {id:111, q:"Ввод воды, слишком малый для потребности здания, скорее всего вызовет:", opts:["Избыточное давление","Только гидроудар","Недостаточный расход и падение давления у приборов","Обратный поток"], re:"Заниженный ввод не способен пропустить нужный расход, поэтому давление падает и приборы испытывают нехватку при высоком спросе."},
  {id:112, q:"Две главные величины, нужные для подбора диаметра трубы ввода воды, — это доступное давление и:", opts:["Цвет трубы","Только число этажей","Стоимость меди","Требуемый расход (потребность), который должно обеспечить здание"], re:"Подбор уравновешивает потребность (нужный расход) с доступным давлением и потерями на трение, которые создаст труба."},
  {id:113, q:"Оцинкованную стальную трубу ввода воды сегодня обычно не рекомендуют главным образом потому, что она:", opts:["Со временем корродирует и ограничивает поток минеральными отложениями","Слишком гибкая","Её нельзя нарезать резьбой","Везде запрещена"], re:"Оцинкованная труба ржавеет изнутри и забивается накипью, снижая расход; обычно предпочитают медь, PEX или пластик."},
  {id:114, q:"Перед подбором диаметра трубопровода здания сантехник должен сначала определить:", opts:["Схему окраски","Доступное статическое (без потока) давление на вводе","Число прочисток","Глубину затвора сифона"], re:"Доступное статическое давление у источника — отправная точка; из него проектировщик вычитает потери на подъём и трение."},
  {id:115, q:"Манометр, подключённый к водоразборному крану без течения воды, показывает давление системы:", opts:["Остаточное","Скорость потока","Статическое","Потери на трение"], re:"При закрытых приборах манометр показывает статическое давление; когда вода течёт, более низкое значение — остаточное давление."},
  {id:116, q:"Система распределения воды внутри здания начинается:", opts:["У городского водохранилища","У каждого крана","На выходе водонагревателя","Там, где заканчивается ввод воды, обычно у водомера или главного запора"], re:"Распределительный трубопровод — это сеть за вводом, которая подаёт воду к приборам и оборудованию по всему зданию."},
  {id:117, q:"Кран-врезка (corporation stop) и колодезный кран (curb stop) — это краны, связанные с:", opts:["Подключением ввода к городской магистрали и у границы участка","Водонагревателем","Системой вентиляции","Плечом сифона"], re:"Кран-врезка врезается в магистраль, а колодезный кран стоит у границы участка — оба на вводе воды до водомера."},
  {id:118, q:"Когда статическое давление воды в подающем трубопроводе превышает 80 psi, кодекс требует:", opts:["Более крупного водомера","Одобренный регулятор давления, чтобы снизить его до 80 psi или менее","Второй ввод воды","Никаких действий ниже 100 psi"], re:"Выше 80 psi статического давления одобренный понижающий клапан с фильтром перед ним должен снизить давление до 80 psi или менее."},
  {id:119, q:"Перед понижающим клапаном (PRV) на вводе воды обычно ставят:", opts:["Только обратный клапан","Второй PRV","Подходящий фильтр (сетку)","Вакуумный прерыватель"], re:"Подходящий фильтр перед регулятором не даёт мусору засорять седло клапана, хотя более крупные регуляторы могут не требовать отдельного фильтра."},
  {id:120, q:"Регуляторы давления для системы распределения питьевой воды должны соответствовать:", opts:["ASSE 1010","NSF для канализации","Никакому стандарту","ASSE 1003 (или AWWA C530)"], re:"Регуляторы давления питьевой воды должны соответствовать ASSE 1003 или AWWA C530, чтобы работать надёжно и безопасно."},
  {id:121, q:"Установка PRV обычно превращает трубопровод здания в:", opts:["Закрытую систему, в которой тепловое расширение может поднять давление","Вентилируемую открытую систему","Самотёчную канализацию","Малоопасную систему, не требующую сброса"], re:"PRV действует как односторонняя преграда, поэтому расширившаяся горячая вода не может уйти обратно в магистраль и нужно устройство контроля расширения."},
  {id:122, q:"Распространённая причина ограничивать давление воды в здании примерно до 80 psi — то, что более высокое давление:", opts:["Экономит воду","Нагружает стыки и приборы и усиливает гидроудар","Улучшает слив","Не имеет недостатков"], re:"Избыточное давление нагружает краны, фитинги, шланги и приборы, увеличивает течи и усиливает толчок гидроудара."},
  {id:123, q:"Остаточное давление (при потоке) отличается от статического тем, что остаточное измеряют:", opts:["При всех закрытых кранах","Только у водомера","Когда вода фактически течёт","У городской магистрали"], re:"Статическое давление — показание без потока; остаточное — то, что остаётся у прибора при заборе воды, после потерь на трение."},
  {id:124, q:"Если источник не может удержать хотя бы около 15 psi остаточного давления у наивысшего прибора, в систему нужно добавить:", opts:["Сифон побольше","Больше прочисток","Вторую вентиляцию","Бак с насосом или иное средство для подъёма давления"], re:"Когда давление в сети слишком мало, чтобы держать около 15 psi у верхних приборов, требуется повысительный насос или система с баком."},
  {id:125, q:"Для приборов, питаемых смывными бачками, минимальное давление при потоке обычно нужно около:", opts:["8 psi","30 psi","60 psi","80 psi"], re:"Обычным приборам со смывным бачком, как правило, нужно лишь около 8 psi при потоке, тогда как смывным клапанам — около 15 psi и более."},
  {id:126, q:"Смывной клапан (прямого смыва) обычно требует минимального давления при потоке не менее примерно:", opts:["3 psi","15 psi","8 psi","2 psi"], re:"Смывные клапаны быстро пропускают большой расход и обычно требуют около 15 psi и более при потоке для правильной работы."},
  {id:127, q:"На каждый фут вертикального подъёма статическое давление воды в столбе падает примерно на:", opts:["0,10 psi","1,0 psi","0,43 psi","2,31 psi"], re:"Вода теряет около 0,43 psi на фут высоты (на 1 psi нужно 2,31 фута столба), поэтому в высоких зданиях вверху давление ниже."},
  {id:128, q:"Подъём на 50 футов снижает статическое давление примерно на:", opts:["Около 5 psi","Около 50 psi","Около 100 psi","Около 22 psi"], re:"При примерно 0,43 psi на фут подъём на 50 футов убирает около 21–22 psi статического давления из подачи."},
  {id:129, q:"PRV обычно настраивают:", opts:["Вращая регулировочный винт, задающий натяжение пружины","Заменяя пружину на медную","Нагревая корпус","Добавляя более крупный фильтр"], re:"Вращение регулировочного винта меняет усилие пружины на мембрану, задавая пониженное давление за клапаном."},
  {id:130, q:"Большинство понижающих клапанов в жилых домах настраивают на выдачу давления за клапаном в диапазоне примерно:", opts:["5–10 psi","45–60 psi","90–110 psi","120–150 psi"], re:"PRV обычно настраивают около 45–60 psi — комфортно ниже предела 80 psi и при этом с хорошей работой приборов."},
  {id:131, q:"Неисправный или застрявший в открытом положении PRV чаще всего проявляется как:", opts:["Полное отсутствие воды","Холодная вода становится горячей","Давление за клапаном поднимается обратно к давлению магистрали","Засорённая вентиляция"], re:"Если PRV отказывает в открытом положении или рвётся мембрана, давление за клапаном растёт к полному давлению магистрали и может превысить 80 psi."},
  {id:132, q:"Чрезмерно высокое домашнее давление чаще всего повреждает такие приборы, как:", opts:["Светильники","Трапы в полу","Кровельные вентиляции","Посудомоечные и стиральные машины и водонагреватели"], re:"Водопотребляющие приборы, их заливные клапаны и шланги нагружаются высоким давлением, что сокращает срок службы и вызывает течи."},
  {id:133, q:"Фильтр перед PRV нужен главным образом, чтобы:", opts:["Улавливать песок и мусор, которые могли бы застрять в седле клапана","Снижать давление","Добавлять хлор","Измерять расход"], re:"Осадок может держать седло регулятора открытым или вызывать его сползание; фильтр улавливает мусор, чтобы PRV продолжал работать."},
  {id:134, q:"Регулятор давления размером 1-1/2 дюйма или больше, как правило:", opts:["Всегда должен иметь два фильтра","Не требует отдельного фильтра","Нельзя применять на питьевой воде","Должен устанавливаться вверх ногами"], re:"Кодексы обычно освобождают регуляторы 1-1/2 дюйма и крупнее от требования отдельного фильтра из-за их конструкции и расхода."},
  {id:135, q:"Нагрузку, которую приборы создают на подающую трубу воды, выражают в:", opts:["Дренажных единицах прибора (DFU)","БТЕ","Водоразборных единицах прибора (WSFU)","Децибелах"], re:"Потребность в воде подсчитывают в водоразборных единицах прибора (WSFU), которые затем переводят в вероятный пиковый расход в gpm."},
  {id:136, q:"Суммарные единицы приборов переводят в вероятную пиковую потребность в галлонах в минуту, используя:", opts:["Закон Ома","Таблицу затворов сифонов","Формулу уклона","Таблицу потребности или кривую Хантера"], re:"Таблица потребности (кривая Хантера) даёт вероятный одновременный расход в gpm для данного числа единиц приборов."},
  {id:137, q:"Потребность в gpm, соответствующая числу единиц приборов, выше, когда унитазы обслуживаются:", opts:["Смывными клапанами (прямого смыва)","Смывными бачками","Водоразборными кранами","Трапами в полу"], re:"Смывные клапаны берут большой мгновенный расход, поэтому при том же числе единиц вероятная потребность в gpm больше, чем со смывными бачками."},
  {id:138, q:"Для прибора с подводками и горячей, и холодной воды каждое отдельное значение единиц для горячей и холодной можно принять примерно как:", opts:["Полное указанное суммарное значение","Три четверти от указанного суммарного","Вдвое больше указанного суммарного","Ноль"], re:"Поскольку горячая и холодная не используются на полную одновременно, каждую ветвь обычно считают как три четверти от указанного суммарного числа единиц."},
  {id:139, q:"Потери на трение в трубе воды растут, когда:", opts:["Диаметр трубы увеличивается","Только вода становится холоднее","Скорость потока растёт или труба длиннее","Давление снижается"], re:"Потери на трение растут с большей скоростью, более длинными участками, меньшим диаметром и более шероховатой трубой, расходуя доступное давление."},
  {id:140, q:"Чтобы ограничить шум и эрозионную коррозию, скорость холодной воды в медной трубе обычно держат на уровне или ниже примерно:", opts:["2 фт/с","20 фт/с","40 фт/с","8 фт/с"], re:"Проектировщики обычно ограничивают скорость холодной воды около 8 фт/с в меди, чтобы избежать шума и эрозии стенки трубы."},
  {id:141, q:"Скорость горячей воды в медной трубе обычно держат ниже, чем у холодной, примерно на уровне:", opts:["5 фт/с","8 фт/с","15 фт/с","25 фт/с"], re:"Горячая вода более агрессивна, поэтому скорость в меди обычно ограничивают около 5 фт/с, чтобы снизить эрозионную коррозию."},
  {id:142, q:"При том же расходе труба меньшего диаметра будет иметь:", opts:["Меньшую скорость и меньшие потери на трение","Большую скорость и большие потери на трение","Без изменения трения","Меньше шума"], re:"Уменьшение диаметра прогоняет тот же расход через меньшую площадь, резко повышая скорость и потери на трение."},
  {id:143, q:"«Развёрнутая длина», используемая при подборе трубы воды, означает:", opts:["Только расстояние по прямой","Диаметр трубы","Полную измеренную длину плюс добавки на фитинги и краны","Только вертикальный подъём"], re:"Развёрнутая длина — это фактическая длина трубы плюс эквивалентная длина, добавленная за фитинги и краны, используемая для суммирования потерь на трение."},
  {id:144, q:"В типичной задаче подбора давление, доступное на преодоление трения трубы, равно давлению источника минус:", opts:["Только стоимость водомера","Цвет трубы","Число приборов","Потери на подъём (статические), нужное давление у прибора и потери на устройствах"], re:"Из давления источника вычитают потери на подъём, минимальное давление у прибора и потери водомера/регулятора/защиты от обратного потока; остаток идёт на трение."},
  {id:145, q:"Добавление множества отводов и фитингов на участок влияет на подбор главным образом тем, что:", opts:["Увеличивает эквивалентную длину и потому потери на трение","Снижает потребность","Уменьшает скорость","Повышает статическое давление"], re:"Каждый фитинг добавляет эквивалентную длину; много фитингов повышают суммарные потери на трение, из-за чего может потребоваться труба большего размера."},
  {id:146, q:"Водоразборному крану, учитываемому при подборе, обычно присваивают единицы прибора, потому что он:", opts:["Никогда не расходует воду","Может брать значительный непрерывный расход","Всегда закрыт","Снижает потребность"], re:"Водоразборный кран может брать большой устойчивый расход, поэтому несёт единицы прибора; дополнительные краны на той же трубе могут учитываться по сниженной норме."},
  {id:147, q:"Непрерывную потребность в расходе, например для полива, при подборе учитывают, когда:", opts:["Её игнорируют","Уменьшают диаметр трубы вдвое","Добавляют её gpm отдельно к потребности по единицам приборов","Считают её одной единицей прибора"], re:"Непрерывные расходы не следуют прерывистой модели единиц прибора, поэтому их gpm добавляют напрямую к потребности соответствующего участка."},
  {id:148, q:"По сравнению с длинным участком короткий участок той же трубы при том же расходе будет иметь:", opts:["Больше потерь на трение","Те же суммарные потери","Без скорости","Меньше суммарных потерь на трение"], re:"Потери на трение пропорциональны длине, поэтому более короткий участок той же трубы и расхода теряет меньше давления на трение."},
  {id:149, q:"Подбор распределения воды так, чтобы каждый прибор получал достаточный расход в пик потребления, важен потому, что:", opts:["Несколько приборов могут работать одновременно и конкурировать за расход","Это снижает счёт за воду","Все трубы должны совпадать","Это устраняет нужду в водомере"], re:"Труба должна нести вероятную одновременную потребность, чтобы открытие одного прибора не лишало воды другой в часы пик."},
  {id:150, q:"Завышение диаметра распределительной трубы воды намного выше потребности может вызвать:", opts:["Лучшую подачу горячей воды","Долгое ожидание горячей воды и потери воды и энергии","Только меньшие проблемы с трением","Более высокое давление у приборов"], re:"Чрезмерно крупная труба горячей воды держит больше остывшей воды, поэтому пользователи дольше ждут и тратят воду и энергию, пока она сливается."},
  {id:151, q:"Вероятная (расчётная) потребность на трубопроводе здания обычно меньше суммы всех расходов приборов, потому что:", opts:["Приборы никогда не работают","Водомер перекрывает поток","Не все приборы используются в один и тот же момент","Давление неограниченно"], re:"Методы единиц приборов учитывают малую вероятность того, что все приборы работают одновременно, поэтому расчётная потребность ниже арифметической суммы."},
  {id:152, q:"Гидроудар — это стук или толчок, возникающий, когда:", opts:["Труба слишком большая","Давление слишком низкое","Сифон слишком глубокий","Быстрозакрывающийся кран резко останавливает движущуюся воду"], re:"Резкая остановка движущегося столба воды превращает его импульс в скачок давления, который трясёт трубопровод."},
  {id:153, q:"Гаситель гидроудара управляет скачком, потому что:", opts:["Создаёт герметичную воздушную подушку, поглощающую толчок","Фильтрует воду","Повышает статическое давление","Нагревает трубу"], re:"Гаситель содержит постоянно герметичную воздушную камеру или поршень, который сжимается, поглощая пик давления."},
  {id:154, q:"Кодекс требует защиты от гидроудара везде, где в системе есть:", opts:["Только смывные бачки","Быстродействующие (быстрозакрывающиеся) краны","Никакого оборудования","Оцинкованная труба"], re:"Системы с быстродействующими кранами должны иметь одобренные устройства для поглощения удара, который эти краны создают при закрытии."},
  {id:155, q:"Заводские гасители гидроудара должны соответствовать:", opts:["Только ASSE 1003","Только NSF 14","ASSE 1010 или PDI-WH 201","Никакому стандарту"], re:"Одобренные гасители соответствуют ASSE 1010 или PDI-WH 201, которые задают требования к рабочим характеристикам и долговечности."},
  {id:156, q:"Гаситель гидроудара следует устанавливать:", opts:["Как можно дальше от крана","Только у водомера","На вентиляционном стояке","Как можно ближе к быстрозакрывающемуся крану"], re:"Размещение гасителя близко к быстрозакрывающемуся крану позволяет ему поглотить скачок до того, как тот пройдёт по трубопроводу."},
  {id:157, q:"Распространённая причина внезапного гидроудара в прачечной — это:", opts:["Соленоидный (быстрозакрывающийся) клапан стиральной машины","Трап в полу","Вентиляция сифона","Водомер"], re:"Соленоидные клапаны стиральной машины резко закрываются, поэтому гасители обычно ставят на её подводки горячей и холодной воды."},
  {id:158, q:"Посудомоечную машину, которая тоже использует быстрозакрывающийся заливной клапан, лучше всего защитить гасителем на:", opts:["Сливной линии","Её подводке горячей воды","Вентиляции","Газовой линии"], re:"Посудомоечная машина берёт горячую воду через быстрозакрывающийся клапан, поэтому гаситель на её горячей подводке поглощает возникающий толчок."},
  {id:159, q:"Воздушные камеры старого типа (заглушённые вертикальные отрезки) со временем перестают работать, потому что они:", opts:["Ржавеют и закрываются","Становятся слишком длинными","Затапливаются, так как захваченный воздух растворяется в воде","Замерзают навсегда"], re:"Воздух в простом отрезке постепенно растворяется в воде, и камера заполняется, поэтому предпочитают современные герметичные гасители."},
  {id:160, q:"Механический (поршневой) гаситель предпочитают простой воздушной камере, потому что он:", opts:["Ничего не стоит","Не требует опоры","Повышает давление","Держит свой воздушный заряд герметичным и не затапливается"], re:"Герметичный поршень или сильфон держит воздух отдельно от воды, поэтому устройство продолжает поглощать толчки в долгосрочной перспективе."},
  {id:161, q:"Помимо гасителей, гидроудар можно уменьшить, если:", opts:["Снизить избыточное давление и закрепить незакреплённые трубы","Увеличить скорость","Убрать все краны","Добавить больше отводов"], re:"Меньшее давление и меньшая скорость ослабляют скачок, а надёжно закреплённая труба передаёт меньше шума и движения."},
  {id:162, q:"Более высокая скорость воды в трубе делает гидроудар:", opts:["Слабее","Сильнее при закрытии крана","Исчезающим","Не зависящим от скорости"], re:"Чем быстрее движущийся столб, тем больший импульс нужно остановить, поэтому быстрое закрытие даёт больший скачок давления."},
  {id:163, q:"Незакреплённый водопровод усиливает гидроудар главным образом потому, что труба:", opts:["Больше течёт","Сильнее нагревается","Может двигаться и биться о каркас при скачке","Меняет размер"], re:"Неопёртая труба хлещет и бьёт по конструкции при скачке; правильное крепление ограничивает движение и шум."},
  {id:164, q:"Гаситель размера «AA» или «A» по PDI-WH 201 обычно предназначен для:", opts:["Целого стояка высотного здания","Пожарного насоса","Канализационной линии","Одного жилого прибора или аппарата"], re:"Размеры PDI, такие как AA и A, подбирают по единицам приборов для отдельных жилых подключений, например стиральной или посудомоечной машины."},
  {id:165, q:"Доступное расположение важно для гасителя гидроудара, чтобы его можно было:", opts:["Осмотреть или заменить при отказе","Покрасить","Использовать как запор","Нагреть"], re:"Гасители со временем могут терять эффективность, поэтому доступ позволяет обслуживать или заменять их при необходимости."},
  {id:166, q:"К быстрозакрывающимся кранам относятся все перечисленные, КРОМЕ:", opts:["Соленоидного клапана стиральной машины","Медленно поворачиваемой задвижки","Заливного клапана посудомоечной машины","Электрического соленоида у льдогенератора"], re:"Задвижка, закрытая медленно вручную, не захлопывается, поэтому она не относится к быстрозакрывающемуся типу, дающему сильный удар."},
  {id:167, q:"Если трубы продолжают стучать после установки одного гасителя, вероятная оставшаяся причина:", opts:["Вода слишком чистая","Слишком много прочисток","Избыточное давление системы или незакреплённый трубопровод в другом месте","Глубокий затвор сифона"], re:"У удара часто несколько источников; высокое давление и незакреплённые участки труб могут продолжать давать шум даже после установки одного гасителя."},
  {id:168, q:"Развёрнутую длину трубы горячей воды от источника до прибора обычно ограничивают примерно:", opts:["10 футами","200 футами","Без ограничения","50 футами"], re:"Кодексы обычно ограничивают развёрнутую длину трубы горячей воды до прибора примерно 50 футами, иначе нужно предусмотреть рециркуляцию или греющий кабель."},
  {id:169, q:"Контур рециркуляции горячей воды используют главным образом для того, чтобы:", opts:["Держать горячую воду у приборов, чтобы пользователь меньше ждал и тратил","Повышать давление воды","Фильтровать воду","Предотвращать обратный поток"], re:"Рециркуляция держит нагретую воду в движении у приборов, чтобы она приходила быстро, а не сливалась холодной в канализацию."},
  {id:170, q:"В системе рециркуляции рециркуляционный трубопровод считается:", opts:["Сливной линией","Источником горячей или подогретой воды для отсчёта предела в 50 футов","Вентиляцией","Веткой холодной воды"], re:"Поскольку контур подаёт горячую воду у приборов, он считается источником, от которого отсчитывают максимальную развёрнутую длину."},
  {id:171, q:"Для экономии энергии трубопровод горячей воды и рециркуляции обычно должен быть:", opts:["Замоноличен в бетон","Окрашен в красный","Изолирован","Оставлен голым для осмотра"], re:"Изоляция трубопровода горячей воды и рециркуляции снижает потери тепла в режиме ожидания, как требует энергетический кодекс."},
  {id:172, q:"Чтобы снизить риск ожогов, горячую воду, подаваемую в ванны и души, обычно ограничивают максимумом примерно:", opts:["100°F","160°F","180°F","120°F"], re:"Около 120°F — обычная максимальная температура подачи для душей и ванн, чтобы снизить риск ожогов."},
  {id:173, q:"Термостатический (смесительный) клапан у водонагревателя используют, чтобы:", opts:["Смешивать горячую и холодную для подачи воды более безопасной заданной температуры","Повышать давление","Предотвращать обратный поток","Сливать бак"], re:"Смесительный клапан ASSE 1017 смешивает горячую воду из бака с холодной до контролируемой пониженной температуры для системы распределения."},
  {id:174, q:"Хранение воды горячее температуры подачи и её последующее подмешивание холодной часто делают, чтобы:", opts:["Тратить энергию","Ограничить рост Legionella, при этом подавая безопасные температуры","Снизить давление","Увеличить расход"], re:"Более высокая температура хранения подавляет бактерию Legionella, а смесительный клапан доводит подаваемую воду до безопасного уровня."},
  {id:175, q:"Тепловое расширение возникает в водонагревателе, потому что нагретая вода:", opts:["Сжимается","Становится плотнее","Расширяется и увеличивается в объёме","Теряет давление"], re:"Вода расширяется при нагреве; в закрытой системе этому добавочному объёму некуда деться, поэтому давление растёт."},
  {id:176, q:"Вода, нагретая примерно с 50°F до 120°F, расширяется примерно на:", opts:["0,02% (почти нисколько)","20% по объёму","50% по объёму","2% по объёму"], re:"Нагрев воды с примерно 50°F до 120°F увеличивает её объём примерно на 2 процента, что поднимает давление в закрытой системе."},
  {id:177, q:"Расширительный бак на водонагревателе требуется всегда, когда система:", opts:["Закрыта обратным клапаном, PRV или защитой от обратного потока","Открыта в атмосферу","Только на скважине","Сделана из пластика"], re:"Обратный клапан, регулятор давления или устройство защиты делают систему закрытой, поэтому требуется расширительный бак или устройство для поглощения теплового расширения."},
  {id:178, q:"Расширительный бак теплового расширения обычно подключают к:", opts:["Выходу горячей воды вдали от нагревателя","Подающему трубопроводу холодной воды к водонагревателю","Сливной линии","Вентиляционному стояку"], re:"Расширительный бак ставят на подаче холодной воды к нагревателю, за любым обратным клапаном, PRV или защитой от обратного потока."},
  {id:179, q:"Мембранный расширительный бак поглощает расширение, используя:", opts:["Нагревательный змеевик","Обратный клапан","Преднакачанную воздушную подушку за гибкой мембраной","Фильтрующую сетку"], re:"При расширении вода давит на мембрану и сжимает захваченный воздух, удерживая давление в безопасных пределах."},
  {id:180, q:"Для лучшей работы предварительную накачку воздуха в расширительном баке следует задать равной:", opts:["Нулю","Удвоенному давлению системы","Всегда 150 psi","Статическому (без потока) давлению воды в системе"], re:"Согласование преднакачки со статическим давлением системы держит мембрану нейтральной, чтобы бак принимал расширение, как только давление растёт."},
  {id:181, q:"Без контроля теплового расширения в закрытой системе наиболее вероятный симптом:", opts:["Предохранительный клапан T&P капает при включении нагревателя","Низкое давление","Нет горячей воды","Засорённый слив"], re:"Растущее от расширения давление может многократно приподнимать предохранительный клапан T&P, заставляя его капать, пока не добавят контроль расширения."},
  {id:182, q:"Предохранительный клапан температуры и давления (T&P) водонагревателя обычно настраивают на открытие не более чем при:", opts:["50 psi","150 psi","80 psi","300 psi"], re:"Жилые клапаны T&P обычно настраивают на сброс при 150 psi (и около 210°F) для защиты бака от избыточного давления."},
  {id:183, q:"Расширительный бак, потерявший воздушный заряд:", opts:["Работает лучше","Намеренно поднимает давление","Заполняется водой и перестаёт поглощать расширение","Сливает нагреватель"], re:"Затопленный бак не может сжиматься, поэтому больше не контролирует расширение, и предохранительный клапан может снова начать капать."},
  {id:184, q:"Рециркуляционный насос в бытовом контуре горячей воды обычно:", opts:["Высоконапорный повысительный насос","Фекальный эжектор","Вакуумный насос","Небольшой циркуляционный насос, гоняющий воду по контуру"], re:"Небольшой малонапорный циркуляционный насос держит горячую воду в движении по контуру; это не повысительный насос для всей системы."},
  {id:185, q:"Там, где давления городской магистрали слишком мало для здания, подачу можно дополнить:", opts:["Поднятым баком, гидропневматической системой или повысительным насосом","Сифоном побольше","Второй вентиляцией","Трапом в полу"], re:"Недостаточное давление магистрали преодолевают поднятым (гравитационным) баком, гидропневматическим напорным баком или повысительным насосом."},
  {id:186, q:"Поднятый (гравитационный) домовый бак подаёт давление в здание за счёт того, что:", opts:["Постоянно работает насос","Использует высоту хранимой воды для создания статического давления","Добавляет химикаты","Нагревает воду"], re:"Вода, хранимая высоко в здании, падает под действием силы тяжести, и её высота даёт статическое давление нижним этажам."},
  {id:187, q:"Гидропневматический (напорный) бак поддерживает давление, используя:", opts:["Нагревательный элемент","Только обратный клапан","Захваченный объём сжатого воздуха над водой","Только силу тяжести"], re:"Сжатый воздух, запертый над водой в герметичном баке, выталкивает воду под давлением, сглаживая цикличность насоса."},
  {id:188, q:"В высотном здании давление воды на верхних этажах ниже, чем на нижних, из-за:", opts:["Меньших водомеров наверху","Более холодной воды","Меньшего числа приборов","Потери статического давления с высотой"], re:"Каждый фут подъёма стоит около 0,43 psi, поэтому на верхних этажах давление ниже и может потребоваться повысительный насос или зонирование."},
  {id:189, q:"Повысительный насос, способный работать при закрытом напорном кране, часто нуждается в защите от:", opts:["Перегрева или избыточного давления (например, защита по малому расходу или сбросная)","Только обратного потока","Только замерзания","Только шума"], re:"Насос, работающий в тупик на закрытую систему, может перегреться или создать избыточное давление, поэтому его защищают средствами управления или сбросным путём."},
  {id:190, q:"Высотные здания часто делят на зоны давления, чтобы нижние этажи не испытывали:", opts:["Слишком малого давления","Чрезмерно высокого давления от всего столба сверху","Обратного потока","Завоздушивания"], re:"Без зонирования самые нижние этажи испытывали бы полный статический напор воды над ними, превышая безопасные пределы давления."},
  {id:191, q:"У каждой подводки прибора обычно есть собственный доступный:", opts:["Вентиляция","Сифон","Запорный (отсечной) кран","Прочистка"], re:"Доступный отсечной кран прибора позволяет изолировать отдельный прибор для ремонта, не отключая всё здание."},
  {id:192, q:"По принятому правилу у подводок прибора, лицом к прибору, горячую воду размещают:", opts:["Справа, а холодную слева","Сверху","Снизу","Слева, а холодную справа"], re:"По давнему правилу горячая слева, а холодная справа у прибора, как и ожидает пользователь."},
  {id:193, q:"Устройство защиты от обратного потока или обратный клапан защищает питьевую подачу, потому что:", opts:["Пропускает поток только в одном направлении, к зданию","Повышает давление","Фильтрует воду","Снижает температуру"], re:"Эти устройства пропускают поток только к приборам и блокируют обратный поток, который мог бы засосать загрязнение обратно в питьевой трубопровод."},
  {id:194, q:"Перекрёстное соединение опасно для питьевой подачи, потому что может позволить:", opts:["Более высокое давление","Непитьевой воде попасть в трубопровод питьевой воды","Более быстрый слив","Меньшие счета"], re:"Перекрёстное соединение связывает питьевую и непитьевую системы; при обратном потоке загрязнённая вода может попасть в питьевую подачу."},
  {id:195, q:"Обратное подсасывание (back-siphonage) — это форма обратного потока, вызванная:", opts:["Высоким давлением на стороне потребителя","Закрытым краном","Отрицательным (ниже атмосферного) давлением в подаче, тянущим воду назад","Тепловым расширением"], re:"Когда давление подачи падает ниже атмосферного, разрежение может затянуть непитьевую воду назад через перекрёстное соединение в систему."},
  {id:196, q:"Водоразборный кран, питающий садовый шланг, нужно защитить от обратного подсасывания:", opts:["Регулятором давления","Вторым водомером","Трубой большего диаметра","Вакуумным прерывателем под шланг"], re:"Вакуумный прерыватель под шланг разрывает любой сифон, чтобы загрязнённую воду нельзя было затянуть назад через шланг в питьевую подачу."},
  {id:197, q:"Воздушный зазор (air gap) защищает питьевую подачу, обеспечивая:", opts:["Незагороженный вертикальный промежуток между выходом и кромкой перелива","Обратный клапан","Больше давления","Фильтр"], re:"Air gap — это физическое вертикальное разделение, чтобы загрязнённую воду никогда нельзя было засосать обратно в выход подачи."},
  {id:198, q:"Там, где повысительный насос забирает из городской магистрали, кодексы опасаются, что разрежение может:", opts:["Улучшить качество воды","Создать отрицательное давление, засасывающее загрязнение обратно в магистраль","Повысить давление магистрали","Нагреть магистраль"], re:"Насос, сильно тянущий из магистрали, может снизить давление ниже атмосферного и засосать загрязнители, поэтому требуются меры защиты."},
  {id:199, q:"Узел защиты от обратного потока по принципу пониженного давления (RP) применяют для защиты питьевой подачи там, где:", opts:["Опасности нет","Давление ниже 8 psi","Нужно защитить высокоопасное перекрёстное соединение","Труба из пластика"], re:"Узел RP даёт наивысший уровень защиты и требуется там, где высокоопасное перекрёстное соединение угрожает питьевой воде."},
  {id:200, q:"После ремонта, при котором вскрывался питьевой трубопровод, обычный шаг для защиты качества воды перед использованием — это:", opts:["Добавить больше давления","Снять водомер","Снизить температуру","Промыть и, где требуется, продезинфицировать затронутый трубопровод"], re:"Вскрытый или новый питьевой трубопровод промывают и, где требуется, дезинфицируют, чтобы внесённые при работе загрязнители не дошли до пользователей."},
  {id:201, q:"Единица дренажного прибора (DFU) — это мера, используемая для того, чтобы:", opts:["Выразить вероятную дренажную нагрузку, которую прибор даёт на систему","Задать давление водоснабжения","Оценить мощность насоса","Подобрать электрическую цепь"], re:"DFU — числовое значение, присвоенное прибору, отражающее его вероятную нагрузку сброса; по нему подбирают сливы и канализацию."},
  {id:202, q:"В таблицах единиц приборов UPC одиночный частный умывальник обычно оценивается примерно в:", opts:["2 DFU","1 DFU","6 DFU","3 DFU"], re:"Одиночный умывальник несёт около 1 единицы дренажного прибора, поскольку его нагрузка сброса невелика."},
  {id:203, q:"Стандартной ванне обычно присваивают дренажную нагрузку около:", opts:["8 DFU","1 DFU","2 DFU","4 DFU"], re:"Ванне обычно присваивают около 2 единиц дренажного прибора в таблицах UPC."},
  {id:204, q:"Бытовую кухонную мойку обычно оценивают по дренажу примерно в:", opts:["1/2 DFU","6 DFU","10 DFU","2 DFU"], re:"Бытовой кухонной мойке обычно присваивают около 2 единиц дренажного прибора."},
  {id:205, q:"Частному унитазу (1,6 gpf) обычно присваивают дренажную нагрузку около:", opts:["3 DFU","8 DFU","12 DFU","1 DFU"], re:"Частному унитазу обычно присваивают около 3 единиц дренажного прибора — наибольшая нагрузка одного бытового прибора."},
  {id:206, q:"По мере роста суммарных единиц приборов, которые несёт слив, требуемый размер трубы обычно:", opts:["Уменьшается","Увеличивается","Становится необязательным","Остаётся прежним"], re:"Больше единиц приборов — больше вероятный поток, поэтому слив должен быть крупнее, чтобы нести нагрузку самотёком."},
  {id:207, q:"Максимальное число единиц приборов, которое может нести горизонтальный слив, зависит главным образом от его диаметра и его:", opts:["Длины вентиляции","Цвета","Уклона (грейда)","Марки фитинга"], re:"Таблицы пропускной способности привязаны к диаметру и уклону трубы, так как больший уклон позволяет трубе нести больше единиц приборов."},
  {id:208, q:"Когда два или более приборов сбрасывают в один слив, этот слив должен быть рассчитан на:", opts:["Половину суммарных единиц приборов","Одну единицу прибора независимо от количества","Только самый крупный отдельный прибор","Суммарное число единиц всех обслуживаемых приборов"], re:"Общий слив рассчитывают на сумму единиц приборов, которые он обслуживает, чтобы он нёс суммарную нагрузку."},
  {id:209, q:"Горизонтальный ответвительный слив диаметром 2 дюйма наиболее уместен для:", opts:["Трапа в полу или небольшой группы моек и ванн","Канализации здания диаметром 6 дюймов","Одного унитаза","Группы из нескольких унитазов"], re:"Ответвление 2 дюйма подходит для лёгких приборов — трапов, ванн и моек; унитазы требуют минимум 3 дюйма."},
  {id:210, q:"Слив прибора определяется как слив, идущий от:", opts:["Прочистки до улицы","Сифона прибора до соединения с любой другой сливной трубой","Вентиляции на крыше до чердака","Водомера до прибора"], re:"Слив прибора идёт от сифона прибора до точки, где он соединяется с другой сливной трубой."},
  {id:211, q:"Сливная труба никогда не может быть меньше, чем:", opts:["Вентиляция, которая его обслуживает","Двойной размер сифона","Сифон или плечо сифона обслуживаемого прибора","Половина размера сифона"], re:"Слив прибора не может быть меньше сифона и плеча сифона, которые он обслуживает, иначе поток будет ограничен."},
  {id:212, q:"По сравнению с частным прибором, тот же прибор при общественном использовании часто получает:", opts:["Ноль единиц прибора","Меньше единиц прибора","Всегда те же единицы прибора","Больше единиц прибора"], re:"Общественные приборы используются чаще, поэтому таблицы нередко присваивают им большее значение единиц прибора, чем частным."},
  {id:213, q:"Минимальный размер сифона и слива для стандартного бытового умывальника:", opts:["1-1/4 дюйма","2 дюйма","3 дюйма","4 дюйма"], re:"Умывальник использует минимальный сифон и слив 1-1/4 дюйма, поскольку его нагрузка сброса небольшая."},
  {id:214, q:"Душевая кабина обычно обслуживается сифоном и сливом не менее:", opts:["1-1/4 дюйма","2 дюйма","3 дюйма","4 дюйма"], re:"Душу требуется минимальный сифон и слив 2 дюйма, чтобы нести его поток без подпора."},
  {id:215, q:"Завышение диаметра слива намного выше требуемых единиц приборов нежелательно, потому что оно может:", opts:["Устранить необходимость в вентиляции","Нести стоки слишком быстро","Снизить промывающее действие и дать осадку оседать","Всегда стоить дешевле"], re:"Завышенный слив идёт мелким потоком, снижая самоочищающую скорость, поэтому осадок оседает и забивает линию."},
  {id:216, q:"Слив здания и канализация здания рассчитываются исходя из:", opts:["Числа окон","Ёмкости водонагревателя","Только площади крыши","Суммарных единиц дренажных приборов всего здания"], re:"Слив и канализацию здания рассчитывают на суммарную нагрузку единиц всех приборов, сбрасывающих в них."},
  {id:217, q:"Кухонная мойка с измельчителем пищевых отходов и посудомоечной машиной обычно:", opts:["Может получить дополнительную дренажную нагрузку и слив 2 дюйма","Должна сливаться в вентиляцию","Не нуждается в сифоне","Несёт ту же нагрузку, что и умывальник"], re:"Дополнительные приборы увеличивают сброс, поэтому мойке обычно дают слив 2 дюйма и большее число единиц прибора."},
  {id:218, q:"Значения единиц приборов существуют для того, чтобы проектировщики могли:", opts:["Совсем не пользоваться таблицами","Привести разные приборы к общему значению нагрузки для подбора","Задать давление газа","Выбирать цвета краски"], re:"Переводя каждый прибор в общую единицу, можно складывать смешанные группы приборов для подбора слива."},
  {id:219, q:"Горизонтальный слив диаметром 3 дюйма обычно несёт:", opts:["Вообще никаких унитазов","Только один умывальник","Больше единиц приборов, чем слив 2 дюйма при том же уклоне","Меньше единиц приборов, чем слив 1-1/2 дюйма"], re:"Больший диаметр несёт большую нагрузку единиц приборов, поэтому слив 3 дюйма справляется с большим, чем 2 дюйма, при том же уклоне."},
  {id:220, q:"Когда применяют таблицы единиц приборов, значения отражают:", opts:["Разрывное давление трубы","Длину вентиляции","Гарантированный одновременный полный поток от каждого прибора","Вероятную, а не одновременно-пиковую нагрузку"], re:"Единицы приборов отражают вероятность одновременного сброса приборов, а не работу всех приборов на полном потоке сразу."},
  {id:221, q:"Горизонтальным сливным трубам диаметром 2-1/2 дюйма и менее обычно задают минимальный уклон:", opts:["1/4 дюйма на фут","1 дюйм на фут","1/2 дюйма на фут","1/8 дюйма на фут"], re:"Небольшие горизонтальные сливы уклоняют не менее чем на 1/4 дюйма на фут, чтобы стоки шли самотёком и осадок уносился."},
  {id:222, q:"Более крупным горизонтальным сливам (3 дюйма и больше) может быть разрешён уклон всего лишь:", opts:["Только 1/4 дюйма на фут","1/8 дюйма на фут, где это одобрено","1 дюйм на фут","Без минимума"], re:"Сливы большего диаметра можно вести с более пологим уклоном 1/8 дюйма на фут, так как их большее сечение всё равно поддерживает поток."},
  {id:223, q:"Сливная труба со слишком крутым уклоном может создавать проблемы, потому что:", opts:["Она всегда замерзает","Вентиляция не нужна","Жидкость может убежать вперёд, оставив осадок позади","Вода течёт вверх"], re:"При очень крутом уклоне вода опережает осадок, оставляя его в трубе, где он накапливается и забивает её."},
  {id:224, q:"Горизонтальный слив, проложенный строго горизонтально (без уклона), склонен:", opts:["Самоочищаться промывкой","Стекать за счёт капиллярности","Течь быстрее","Давать стокам застаиваться, а осадку — оседать"], re:"Без уклона нет самотёка, поэтому стоки застаиваются в трубе, а осадок оседает и блокирует её."},
  {id:225, q:"Уклон 1/4 дюйма на фут означает, что труба опускается на:", opts:["1/4 дюйма на каждый фут горизонтального участка","1 фут на каждые 1/4 дюйма","4 дюйма на фут","1/4 дюйма на всю длину"], re:"Уклон 1/4 дюйма на фут опускает трубу на четверть дюйма падения на каждый фут горизонтали."},
  {id:226, q:"Цель поддержания правильного уклона слива — сохранять поток на скорости, которая:", opts:["Как можно медленнее","Самоочищает, унося осадок","Ровно ноль","Достаточно быстра, чтобы выплёскиваться в вентиляцию"], re:"Правильный уклон даёт самоочищающую скорость, которая держит осадок в движении и не даёт трубе засоряться."},
  {id:227, q:"На горизонтальном участке 12 футов уклон 1/4 дюйма на фут даёт суммарное падение около:", opts:["Без падения","1 дюйм","3 дюйма","12 дюймов"], re:"При 1/4 дюйма на фут двенадцать футов участка опускаются примерно на 3 дюйма в сумме (12 x 1/4 дюйма)."},
  {id:228, q:"На какую силу в первую очередь опирается сливная труба для перемещения стоков?", opts:["Разрежение из вентиляции","Давление водоснабжения","Давление насоса","Сила тяжести"], re:"Самотёчная система слива использует уклон трубы и силу тяжести, а не давление, чтобы нести стоки в канализацию."},
  {id:229, q:"Изменение направления горизонтального слива следует выполнять фитингами, которые:", opts:["Сохраняют плавный поток, например отводы большого радиуса или комбинированные фитинги","Меняют уклон на обратный","Убирают уклон","Резко поворачивают поток на 90 градусов в горизонтали"], re:"Плавные фитинги с большим радиусом сохраняют поток и сопротивляются засорам, тогда как резкие горизонтальные повороты задерживают осадок."},
  {id:230, q:"Если горизонтальный слив приходится вести положе минимального уклона, обычное решение —:", opts:["Использовать трубу меньшего диаметра","Увеличить диаметр трубы или установить насос","Убрать сифон","Добавить больше фитингов"], re:"Труба большего диаметра несёт нагрузку при более пологом уклоне; где падения нет, применяют одобренный канализационный насос или эжектор."},
  {id:231, q:"Слив здания ниже уровня городской канализации обычно требует:", opts:["Никаких особых мер","Только более крутого самотёчного уклона","Канализационного эжектора или дренажного насоса для подъёма стоков","Только более крупной вентиляции"], re:"Приборы ниже канализации не могут стекать самотёком, поэтому их стоки собирают в приямок и перекачивают вверх в самотёчный слив."},
  {id:232, q:"На сливе с уклоном термин 'invert' (лоток) обозначает:", opts:["Наружное покрытие","Крышку прочистки","Верхнюю внутреннюю часть трубы","Самую нижнюю внутреннюю поверхность трубы"], re:"Лоток — это самая нижняя внутренняя точка трубы; уклон измеряют по лотку, чтобы задать правильное падение."},
  {id:233, q:"Правильный уклон проверяют при монтаже главным образом для того, чтобы обеспечить:", opts:["Непрерывное падение к канализации без провисов и обратного уклона","Горизонтальность трубы","Более короткую вентиляцию","Чтобы труба выглядела прямой"], re:"Проверка уклона подтверждает непрерывное падение к канализации; низкая точка (провис) или обратный уклон удерживали бы стоки и забивали трубу."},
  {id:234, q:"'Провис' (прогиб) в горизонтальном сливе — это дефект, потому что он:", opts:["Ускоряет слив","Скапливает стоячую воду и стоки, приводя к засорам","Улучшает вентиляцию","Увеличивает уклон"], re:"Прогиб создаёт низкую точку, где вода и осадок скапливаются вместо того, чтобы течь дальше, в итоге блокируя линию."},
  {id:235, q:"Сливную трубу нужно поддерживать с интервалами, достаточно частыми, чтобы:", opts:["Позволить трубе свободно изгибаться","Устранить необходимость в уклоне","Предотвратить провисание, которое разрушило бы уклон","Сделать трубу тяжелее"], re:"Достаточные подвесы и опоры не дают трубе провисать между опорами, что создавало бы провисы и портило уклон."},
  {id:236, q:"Глубина водяного затвора сифона обычно должна быть не менее:", opts:["6 дюймов","1/2 дюйма","1 дюйм","2 дюйма"], re:"Затвор сифона должен быть не менее 2 дюймов глубиной, чтобы надёжно блокировать канализационный газ в здание."},
  {id:237, q:"Водяной затвор сифона обычно ограничен максимальной глубиной около:", opts:["4 дюйма","12 дюймов","24 дюйма","Без максимума"], re:"Затворы сифона держат в пределах 2–4 дюймов; более глубокие затворы могут удерживать осадок и не являются стандартом."},
  {id:238, q:"'Порог' (weir) сифона — это:", opts:["Пробка прочистки","Верх выходного колена, где вода переливается в плечо сифона","Отверстие вентиляции","Вход сифона от прибора"], re:"Порог — это гребень, через который вода выходит из сифона в плечо; затвор измеряют от нижней точки (dip) до порога."},
  {id:239, q:"Трап в полу, используемый редко, может потерять затвор из-за испарения; это обычно предотвращают с помощью:", opts:["Более глубокого уклона","Более крупной вентиляции","Заправщика сифона, периодически добавляющего воду","Второго сифона"], re:"Заправщик сифона подаёт небольшое количество воды в сифон, восполняя испарение и сохраняя затвор."},
  {id:240, q:"Самый распространённый сифон, применяемый на бытовых приборах, —:", opts:["Колоколообразный сифон","S-сифон","Барабанный сифон","P-сифон"], re:"P-сифон с горизонтальным плечом к вентиляции — это стандартный одобренный сифон прибора."},
  {id:241, q:"Потеря затвора сифона опасна главным образом потому, что она допускает:", opts:["Проникновение канализационного газа в здание","Повышенное давление воды","Обратный поток питьевой воды","Гидроудар"], re:"Если затвор потерян, канализационные газы (которые могут быть токсичны и горючи) проходят через пустой сифон в помещение."},
  {id:242, q:"Сифон может потерять затвор из-за самосрыва, который представляет собой:", opts:["Замерзание воды в сифоне","Сброс прибора, увлекающий за собой воду затвора","Испарение за месяцы","Ветер над вентиляцией"], re:"Самосрыв происходит, когда собственный сброс прибора создаёт разрежение, вытягивающее воду затвора из невентилируемого сифона."},
  {id:243, q:"Затвор сифона также может быть потерян из-за противодавления, которое вызвано:", opts:["Слишком большим уклоном","Отсутствием прочистки","Положительным давлением в сливе, выдувающим затвор в сторону прибора","Холодной погодой"], re:"Положительное давление, поднимающееся по стояку, может вытолкнуть воду затвора из сифона в прибор, срывая затвор."},
  {id:244, q:"Каждый прибор, кроме приборов со встроенным сифоном, обязан иметь:", opts:["Общий сифон со следующим прибором","Два сифона","Никакого сифона","Свой отдельный сифон"], re:"Каждый сантехнический прибор должен иметь отдельный сифон (если сифон не встроен), чтобы канализационный газ был заблокирован у каждого прибора."},
  {id:245, q:"Унитазу не нужен отдельный накладной сифон, потому что он:", opts:["Имеет встроенный в прибор сифон","Использует воздушный зазор","Сливается в барабанный сифон","Вентилируется иначе"], re:"У унитаза сифон отлит в керамике, поэтому дополнительный наружный сифон на него не ставят."},
  {id:246, q:"Расстояние от порога сифона до его нижней точки (dip) определяет:", opts:["Длину плеча сифона","Глубину затвора сифона","Диаметр вентиляции","Уклон слива"], re:"Глубина затвора — это вертикальное расстояние между нижней точкой и порогом; оно должно быть не менее 2 дюймов."},
  {id:247, q:"Материал сифона, например ABS или хромированная латунь, должен быть:", opts:["Больше выпуска прибора на 2 дюйма","Заполнен песком","С гладким каналом и коррозионностойким","Сделан из свинца"], re:"Одобренные материалы сифона гладкие внутри и стойки к коррозии, чтобы затвор держался, а стоки не цеплялись за шероховатости."},
  {id:248, q:"Стандартный P-сифон следует устанавливать так, чтобы сифон был:", opts:["Наклонён так, чтобы затвор стекал","Только внутри стенной полости","Выше кромки перелива","Горизонтально и ниже прибора, с целым затвором"], re:"Сифон ставят горизонтально под прибором, чтобы он удерживал полный затвор 2 дюйма, а плечо могло уклоняться к вентиляции и сливаться."},
  {id:249, q:"S-сифон запрещён главным образом потому, что он:", opts:["Склонен к самосрыву и потере затвора","Не может подключиться к прибору","Слишком велик для любого слива","Слишком дорог"], re:"S-сифон сбрасывает прямо вниз, что самосрывает воду затвора; вместо него требуется вентилируемый P-сифон."},
  {id:250, q:"Колоколообразный сифон не допускается, потому что он:", opts:["Имеет слишком глубокий затвор","Легко теряет затвор и труден в очистке и обслуживании","Предназначен только для унитазов","Не требует вентиляции"], re:"Колоколообразные сифоны легко теряют затвор, а их съёмные части легко теряются или забиваются, поэтому они запрещены."},
  {id:251, q:"Барабанный сифон обычно запрещён или не рекомендуется, потому что он:", opts:["Слишком мал для использования","Хорошо самоочищается","Накапливает мусор и труден в очистке и правильной вентиляции","Не имеет затвора"], re:"Барабанные сифоны склонны накапливать осадок, их трудно чистить и вентилировать, поэтому современные нормы их ограничивают или запрещают."},
  {id:252, q:"Двойной сифон на одном приборе запрещён, потому что воздух, запертый между двумя сифонами:", opts:["Ускоряет поток","Увеличивает глубину затвора","Улучшает затвор","Не имеет пути для вентиляции и вызывает вялый слив и потерю затвора"], re:"Воздух, запертый между двумя сифонами, не может выйти, поэтому слив идёт медленно, а затворы склонны вытягиваться или выдуваться."},
  {id:253, q:"Сифон, который зависит от подвижных частей или перегородки для удержания затвора:", opts:["Как правило, запрещён","Обязателен для трапов в полу","То же, что P-сифон","Предпочтителен для моек"], re:"Сифоны, зависящие от подвижных частей, внутренних перегородок или скрытых механизмов, запрещены, поскольку затвор ненадёжен."},
  {id:254, q:"Плечо сифона — это часть трубы, идущая от:", opts:["Выхода вентиляции до крыши","Порога сифона до подключения вентиляции","Кромки прибора до сифона","Прочистки до канализации"], re:"Плечо сифона идёт от выхода сифона (порога) до точки, где вентиляция подключается к сливу."},
  {id:255, q:"Для плеча сифона диаметром 1-1/4 дюйма максимальная развёрнутая длина до вентиляции составляет около:", opts:["Без ограничения","6 дюймов","30 дюймов","10 футов"], re:"Плечо сифона 1-1/4 дюйма может быть до примерно 30 дюймов (2-1/2 фута), прежде чем сифону грозит самосрыв."},
  {id:256, q:"Для плеча сифона диаметром 1-1/2 дюйма максимальная длина до вентиляции составляет около:", opts:["8 футов","Без ограничения","18 дюймов","42 дюйма"], re:"Плечо сифона 1-1/2 дюйма ограничено примерно 42 дюймами (3-1/2 фута) развёрнутой длины до вентиляции."},
  {id:257, q:"Для плеча сифона диаметром 2 дюйма максимальная развёрнутая длина до вентиляции составляет около:", opts:["5 футов","20 футов","Без ограничения","2 фута"], re:"Плечо сифона 2 дюйма может тянуться около 5 футов до вентиляции по таблице длины плеча сифона."},
  {id:258, q:"Для плеча сифона диаметром 3 дюйма максимальная развёрнутая длина до вентиляции составляет около:", opts:["3 фута","6 футов","30 футов","Без ограничения"], re:"Плечо сифона 3 дюйма обычно ограничено примерно 6 футами развёрнутой длины до вентиляции."},
  {id:259, q:"Плечо сифона до его вентиляции ни в коем случае не должно быть короче, чем:", opts:["Половина затвора сифона","Ширина прибора","Двойной диаметр плеча сифона","Высота вентиляции"], re:"Плечо сифона должно быть не менее двух диаметров трубы, чтобы подключение вентиляции не затапливалось сбросом сифона."},
  {id:260, q:"Ограничение длины плеча сифона защищает сифон главным образом от:", opts:["Гидроудара","Высокого давления подачи","Замерзания","Самосрыва, который опустошил бы затвор"], re:"Если плечо сифона слишком длинное, падающий сброс может сорвать затвор; ограничение длины предотвращает этот самосрыв."},
  {id:261, q:"Вентиляция сифона должна подключаться к плечу сифона:", opts:["На уровне порога сифона или выше","Только у кромки прибора","В любой точке слива здания","Ниже порога сифона"], re:"Вентиляция подключается на уровне порога или выше, чтобы плечо сифона не заполнялось и не затапливало отверстие вентиляции стоками."},
  {id:262, q:"Плечо сифона не должно иметь вертикального падения больше собственного диаметра до выхода на вентиляцию, чтобы избежать:", opts:["Более крупного сифона","Воссоздания эффекта самосрыва S-сифона","Более крупной вентиляции","Второго сифона"], re:"Избыточное вертикальное падение в плече сифона создаёт условие S-сифона, способное сорвать затвор, поэтому падение ограничивают."},
  {id:263, q:"Соединять два прибора так, чтобы они делили один сифон (кроме одобренного комплекта):", opts:["Разрешено только для унитазов","Всегда обязательно","Как правило, запрещено","Рекомендуется для ванн"], re:"Приборы должны иметь отдельные сифоны, кроме одобренных сочетаний, поэтому общий один сифон обычно не допускается."},
  {id:264, q:"Главное назначение системы вентиляции:", opts:["Подавать воду приборам","Отапливать здание","Нести стоки в канализацию","Впускать воздух для защиты затворов сифонов и выравнивания давления в сливах"], re:"Вентиляция впускает воздух, чтобы слив шёл свободно, а затворы сифонов не срывались и не выдувались при перепадах давления."},
  {id:265, q:"Индивидуальная (обратная) вентиляция обслуживает:", opts:["Сифон одного прибора","Только слив здания","Только водонагреватель","Каждый прибор в здании"], re:"Индивидуальная вентиляция подключается к сифону одного прибора и защищает его, вентилируя этот прибор отдельно."},
  {id:266, q:"Общая (common) вентиляция — это одна вентиляция, обслуживающая:", opts:["Никаких приборов","Два прибора, соединённых на одном уровне","Восемь и более унитазов","Всё здание"], re:"Общая вентиляция обслуживает два прибора, чьи сливы соединяются на одном уровне, вентилируя оба через одну трубу."},
  {id:267, q:"Мокрая (wet) вентиляция — это труба, которая работает как:", opts:["Прочистка","Только вентиляция","Одновременно слив для одного прибора и вентиляция для другого","Линия водоснабжения"], re:"Мокрая вентиляция несёт слив одного прибора и одновременно служит вентиляцией для другого прибора группы."},
  {id:268, q:"Контурную (circuit) вентиляцию применяют для вентиляции:", opts:["Только крыши","Водонагревателя","Одного умывальника","Батареи приборов на горизонтальном ответвлении через одну вентиляцию"], re:"Контурная вентиляция обслуживает ряд (батарею) приборов на горизонтальном ответвлении, вентилируя их одной вентиляцией перед последним прибором."},
  {id:269, q:"Вентиляционный стояк (vent stack) — это вертикальная вентиляционная труба, установленная главным образом для того, чтобы:", opts:["Обеспечивать циркуляцию воздуха к системе слива и от неё","Подавать холодную воду","Удерживать затвор сифона","Отводить стоки"], re:"Вентиляционный стояк — это вертикальная вентиляция, которая обеспечивает циркуляцию воздуха по системе слива, нередко разгружая стояк на нескольких этажах."},
  {id:270, q:"Вытяжная часть стояка (stack vent) — это:", opts:["Отдельная водопроводная труба","Продолжение фекального или сточного стояка выше самого верхнего ответвления","Жироуловитель","Заправщик сифона"], re:"Stack vent — это сухое продолжение фекального или сточного стояка выше самого верхнего горизонтального слива, подключённого к этому стояку."},
  {id:271, q:"Вентиляционные трубы должны быть уклонены и соединены так, чтобы они:", opts:["Шли вверх к крыше","Удерживали стоячую воду","Отводили любой конденсат обратно в слив самотёком","Уклонялись в сторону от стояка"], re:"Вентиляцию уклоняют так, чтобы влага стекала обратно в сливную трубу и не скапливалась, перекрывая воздушный проход."},
  {id:272, q:"Там, где вентиляция выходит через крышу, она должна возвышаться над крышей не менее чем примерно на:", opts:["2 дюйма","3 фута","10 футов","6 дюймов"], re:"Выход вентиляции должен подниматься не менее чем на 6 дюймов над крышей, чтобы снег или застой воды его не перекрывали."},
  {id:273, q:"Выход вентиляции следует держать от открывающегося окна или воздухозаборника на расстоянии не менее:", opts:["10 футов по горизонтали (или заканчиваться на 3 фута выше)","100 футов","6 дюймов","1 фут"], re:"Чтобы канализационный газ не попадал в здание, вентиляция должна быть не менее чем в 10 футах от проёма или заканчиваться на 3 фута выше него."},
  {id:274, q:"Минимальный размер для большинства индивидуальных вентиляций:", opts:["1/2 дюйма","1-1/4 дюйма","3 дюйма","4 дюйма"], re:"Вентиляции обычно не меньше 1-1/4 дюйма, и вентиляция должна быть не менее половины диаметра обслуживаемого слива."},
  {id:275, q:"Диаметр вентиляции обычно должен быть не менее:", opts:["Одной десятой диаметра слива","Двойного диаметра слива","Половины диаметра обслуживаемого слива","Того же, что и водопроводный ввод"], re:"Вентиляция должна быть не менее половины диаметра обслуживаемого слива, с минимальным предельным размером, чтобы впускать достаточно воздуха."},
  {id:276, q:"Воздушный впускной клапан (AAV), где он разрешён, работает так, что:", opts:["Качает воду","Заменяет сифон","Выпускает канализационный газ в помещение","Открывается для впуска воздуха при разрежении и герметизируется при положительном давлении"], re:"AAV открывается, впуская воздух, когда слив создаёт разрежение, и закрывается при положительном давлении, чтобы газ не мог выйти."},
  {id:277, q:"Разгрузочная (relief) вентиляция предусматривается главным образом для того, чтобы:", opts:["Сбрасывать давление между сливным стояком и горизонтальным ответвлением","Подавать горячую воду","Задерживать осадок","Сливать приборы"], re:"Разгрузочная вентиляция даёт дополнительный путь воздуху, чтобы перепады давления в стояке не влияли на затворы сифонов ответвления."},
  {id:278, q:"Вентиляционная труба, идущая горизонтально, должна оставаться выше:", opts:["Линии крыши","Кромки перелива обслуживаемых приборов","Только слива здания","Водомера"], re:"Горизонтальные участки вентиляции должны быть выше кромки перелива приборов, чтобы стоки не могли попасть в вентиляцию."},
  {id:279, q:"Прибор, который недостаточно вентилируется, чаще всего страдает от:", opts:["Избыточного уклона","Высокого давления воды","Медленного булькающего слива и сорванного затвора сифона","Замёрзших труб"], re:"Без вентиляции сифон может быть сорван, а воздух не может войти, поэтому прибор сливается медленно и булькает по мере вытягивания затвора."},
  {id:280, q:"В санузловой группе с мокрой вентиляцией мокрую вентиляцию обычно завышают по диаметру, чтобы она могла:", opts:["Удерживать больше затвора сифона","Заменить слив здания","Служить прочисткой","Нести слив и при этом пропускать воздух для вентиляции остальных приборов"], re:"Мокрую вентиляцию увеличивают, чтобы она несла сброс одного прибора и при этом оставляла воздушный путь для вентиляции остальных."},
  {id:281, q:"Прочистку предусматривают в системе слива, чтобы:", opts:["Дать доступ для устранения засоров без разрезания трубы","Уменьшить размер трубы","Удерживать затвор сифона","Вентилировать линию"], re:"Прочистка даёт доступ, чтобы слив можно было пробить тросом или прочистить от засора, не разбирая трубу."},
  {id:282, q:"На длинном горизонтальном сливе прочистки обычно требуются с интервалом не более:", opts:["10 футов","100 футов развёрнутой длины","500 футов","1 000 футов"], re:"Прочистка требуется на каждые 100 футов (или их часть) развёрнутой длины горизонтального слива, чтобы можно было достать любую точку."},
  {id:283, q:"Прочистка также требуется там, где суммарное изменение направления на участке слива превышает около:", opts:["45 градусов","90 градусов","135 градусов","360 градусов"], re:"Дополнительная прочистка требуется там, где горизонтальные изменения направления в сумме превышают 135 градусов, так как повороты мешают прочистке тросом."},
  {id:284, q:"Прочистку необходимо устанавливать в верхнем конце:", opts:["Вентиляционного стояка","Газовой линии","Линии водоснабжения","Каждого горизонтального сливного участка"], re:"Каждому горизонтальному сливному участку нужна прочистка в его верхнем конце, чтобы трос можно было провести вниз по всей линии."},
  {id:285, q:"Прочистки нужно устанавливать так, чтобы они были:", opts:["Легкодоступны для очистки слива","Всегда на крыше","Внутри затвора сифона","Зарыты и герметично закрыты навсегда"], re:"Прочистка бесполезна, если до неё не добраться, поэтому она должна оставаться легкодоступной для обслуживания слива."},
  {id:286, q:"Прочистку обычно можно не ставить на горизонтальном сливе короче, чем:", opts:["Исключений нет","5 футов (кроме случая, когда он обслуживает мойки или писсуары)","50 футов","100 футов"], re:"Очень короткие горизонтальные сливы менее 5 футов могут обходиться без прочистки, кроме случаев, когда они обслуживают мойки или писсуары."},
  {id:287, q:"Жироуловитель (жировую ловушку) устанавливают, чтобы:", opts:["Повысить давление воды","Добавлять воду в сифон","Не пускать жиры, масла и жир в канализацию здания","Вентилировать кухню"], re:"Жироуловитель отделяет и задерживает жиры, масла и жир, чтобы они не попадали и не забивали систему канализации."},
  {id:288, q:"Жироуловитель чаще всего требуется на сливе от:", opts:["Газонного дождевателя","Кровельного водостока","Бытовой ванны","Моек и посудомоечной машины коммерческой кухни"], re:"Коммерческие кухни сбрасывают большие количества жира, поэтому их посудомоечные приборы сливаются через жироуловитель."},
  {id:289, q:"Гидромеханический жироуловитель обычно имеет номинальный расход не менее примерно:", opts:["20 gpm","200 gpm","2 000 gpm","2 gpm"], re:"Сертифицированные по нормам гидромеханические жироуловители обычно начинаются примерно с 20 gpm пропускной способности."},
  {id:290, q:"Унитазу обычно не разрешают сбрасывать через жироуловитель, потому что уловитель предназначен только для:", opts:["Хозяйственно-фекальных стоков от унитазов","Жирных стоков, а не фекальных стоков","Ливневой воды","Воздуха вентиляции"], re:"Жироуловители обрабатывают жирные стоки приборов; стоки унитаза (чёрные) держат отдельно, чтобы они не загрязняли уловитель."},
  {id:291, q:"Песко- или нефтеуловитель применяют, чтобы удержать:", opts:["Воду в сифоне","Только жир","Песок, нефть или другие тяжёлые материалы вне системы слива","Газ вентиляции в трубе"], re:"Песко- и нефтеуловители отделяют тяжёлый осадок и нефтепродукты (как в гаражах и автомойках) до слива."},
  {id:292, q:"Слив здания — это самая нижняя горизонтальная сливная труба, которая:", opts:["Подаёт воду","Вентилирует стояки","Идёт по крыше","Принимает сброс всех сливов здания и несёт его в канализацию здания"], re:"Слив здания — это самая нижняя часть системы слива внутри здания, собирающая все стоки и выводящая их наружу в канализацию."},
  {id:293, q:"Слив здания обычно становится канализацией здания в точке примерно:", opts:["В 2 футах за стеной здания","У вентиляции на крыше","У водомера","У сифона прибора"], re:"По определению слив здания тянется примерно на 2 фута за стену здания, где он становится канализацией здания."},
  {id:294, q:"Канализация здания несёт стоки от слива здания до:", opts:["Водонагревателя","Городской канализации или одобренной частной системы отведения","Кровельного водостока","Выхода вентиляции"], re:"Канализация здания проводит стоки здания от слива здания до городской канализации или одобренной системы локального отведения."},
  {id:295, q:"Дождевая (ливневая) вода и кровельные водостоки, как правило:", opts:["Подключаются к вентиляции","Сбрасываются в фекальную канализацию вместе с унитазами","Держатся отдельно от фекальной системы слива","Направляются через жироуловитель"], re:"Ливневую воду обычно держат вне хозяйственно-фекальной системы и отводят отдельной ливневой системой."},
  {id:296, q:"Прочистка на стыке слива здания и канализации здания позволяет сервисному технику:", opts:["Добавить сифон","Увеличить уклон","Вентилировать канализацию","Пробить тросом канализацию здания в сторону улицы"], re:"Прочистка возле стыка здание/канализация даёт доступ, чтобы пробить тросом канализацию здания в сторону уличной сети."},
  {id:297, q:"Сифон здания (домовый сифон), где он применяется, предназначен для того, чтобы:", opts:["Обеспечить единый затвор между сливом здания и городской канализацией","Качать стоки вверх","Заменить сифоны приборов","Вентилировать здание"], re:"Сифон здания ставит один затвор на слив здания, чтобы блокировать канализационные газы из сети; многие нормы теперь ограничивают его в пользу сифонов приборов и вентиляции."},
  {id:298, q:"Подземную сливную трубу здания обычно требуется заглублять под поверхность не менее чем примерно на:", opts:["1 дюйм","12 дюймов (1 фут)","6 футов","Без минимума"], re:"Сливную трубу под зданием или рядом с ним обычно держат не менее чем примерно на 12 дюймов ниже уровня грунта, чтобы защитить её от повреждений."},
  {id:299, q:"Минимальный размер для слива или канализации здания, обслуживающих один или более унитазов:", opts:["1-1/2 дюйма","2 дюйма","3 дюйма","Без минимума"], re:"Поскольку унитазу нужен слив 3 дюйма, любой слив или канализация здания, несущие унитаз, должны быть не менее 3 дюймов."},
  {id:300, q:"Перед обратной засыпкой подземной канализации здания монтажник должен:", opts:["Снять прочистки","Подключить её к вентиляции","Пропустить любую проверку","Проверить линию на течи и подтвердить правильный уклон"], re:"Канализацию проверяют на герметичность и убеждаются в непрерывном уклоне до засыпки, так как дефекты трудно исправить после закапывания."},
  {id:301, q:"Унитаз со смывным клапаном (флашометром) отличается от бачкового унитаза тем, что он:", opts:["Подключается напрямую к водопроводу и дозирует воду через клапан, без накопительного бачка","Всегда расходует более 5 галлонов на смыв","Хранит смывную воду в самотёчном бачке","Не может применяться в коммерческих зданиях"], re:"Флашометр подключается напрямую к водопроводу и выпускает дозированный поток через клапан, поэтому ему не нужен накопительный бачок — вот почему он распространён в общественных туалетах."},
  {id:302, q:"Для работы смывного клапана (флашометра) подающий трубопровод должен обеспечивать:", opts:["Очень малый расход в течение длительного времени","Полное отсутствие минимального давления","Достаточный напор и расход, чтобы клапан срабатывал быстро","Только самотёк из бака на крыше"], re:"Поскольку флашометр выпускает короткий поток с высоким расходом, ответвление должно обеспечивать достаточный напор и расход для работы клапана; труба недостаточного сечения не даёт ему сработать."},
  {id:303, q:"Самотёчный бачковый унитаз создаёт смыв за счёт:", opts:["Насоса в чаше","Электрического соленоида","Только сжатого воздуха","Высвобождения веса и объёма воды, хранящейся в бачке"], re:"Самотёчный унитаз использует напор и объём воды, падающей из бачка, чтобы создать сифонный эффект в чаше — вот почему бачковые унитазы преобладают в домах."},
  {id:304, q:"Унитаз с двойным смывом предназначен для того, чтобы:", opts:["Давать уменьшенный смыв для жидких отходов и полный смыв для твёрдых","Смывать только горячей водой","Использовать две отдельные линии водоснабжения","Требовать смывной клапан (флашометр)"], re:"Унитазы с двойным смывом дают частичный смыв для жидкостей и полный смыв для твёрдых отходов, экономя воду на более частых лёгких смывах."},
  {id:305, q:"Федеральный максимальный объём смыва для стандартного нового унитаза составляет:", opts:["3,5 галлона на смыв","5,0 галлона на смыв","1,6 галлона на смыв","2,5 галлона на смыв"], re:"Национальный стандарт ограничивает стандартный унитаз 1,6 галлона на смыв; высокоэффективные модели расходуют ещё меньше."},
  {id:306, q:"Высокоэффективный унитаз (с маркировкой WaterSense) расходует не более:", opts:["1,6 галлона на смыв","2,0 галлона на смыв","1,28 галлона на смыв","3,5 галлона на смыв"], re:"Унитазы WaterSense ограничены 1,28 галлона на смыв — примерно на 20% меньше федерального стандарта 1,6 галлона на смыв."},
  {id:307, q:"В Калифорнии максимальный расход, допустимый для бытового душевого распылителя, составляет:", opts:["1,8 галлона в минуту","2,5 галлона в минуту","3,0 галлона в минуту","5,0 галлона в минуту"], re:"Калифорния ограничивает душевые распылители 1,8 галлона в минуту; там, где несколько распылителей подключены к одному вентилю, их суммарный расход не должен превышать это значение."},
  {id:308, q:"Когда несколько душевых распылителей обслуживаются одним управляющим вентилем, суммарный расход должен:", opts:["Удваиваться для каждого распылителя","Быть неограниченным","Не превышать предел для одного распылителя при испытательном давлении","Измеряться только на счётчике"], re:"Калифорния рассматривает распылители на одном вентиле как единое целое; вместе они не могут превышать 1,8 галлона в минуту при 80 psi, поэтому добавление распылителей не обходит ограничение."},
  {id:309, q:"Смывной клапан писсуара в общественном туалете чаще всего является:", opts:["Самотёчным бачком","Ручным наливным ведром","Только ножным насосом","Клапаном типа флашометр (смывной клапан)"], re:"Писсуары обычно обслуживаются смывными клапанами (флашометрами), подключёнными напрямую к водопроводу — тем же семейством клапанов, что и коммерческие унитазы."},
  {id:310, q:"Конструкция чаши типа «сифон-джет» относится к унитазу, который:", opts:["Использует струю воды для запуска сифона и очистки чаши","Не имеет сифона","Сливается только за счёт давления воздуха","Не может удерживать водяной затвор"], re:"«Сифон-джет» направляет воду через струю в канале сифона, чтобы запустить сифонный эффект, обеспечивая сильный, тихий смыв и большую водную поверхность."},
  {id:311, q:"Напольный унитаз уплотняется к фланцу выпуска с помощью:", opts:["Силиконовой ленты","Растворного клея","Только сантехнической замазки","Воскового кольца (или одобренной прокладки)"], re:"Восковое кольцо или сертифицированная безвосковая прокладка уплотняет выпуск унитаза к фланцу, чтобы стоки и канализационный газ не выходили на уровне пола."},
  {id:312, q:"Поплавковый клапан (заливной клапан) внутри бачка самотёчного унитаза отвечает за:", opts:["Дозаполнение бачка и чаши после смыва","Нагрев воды","Отвод канализационного газа","Закрытие домового запорного вентиля"], re:"Заливной клапан дозаполняет бачок до заданного уровня и подаёт воду в чашу после каждого смыва, чтобы сифон восстановил затвор, а бачок был готов к работе."},
  {id:313, q:"Переливная трубка в бачке унитаза существует для того, чтобы:", opts:["Ускорить смыв","Заменить клапан-лепесток","Повысить давление в бачке","Отводить избыток воды в чашу, а не на пол"], re:"Если заливной клапан не закрывается, переливная трубка направляет лишнюю воду вниз в чашу и в слив, а не переливает её через край бачка."},
  {id:314, q:"Унитаз с нагнетательным смывом улучшает смыв за счёт:", opts:["Использования бака на крыше","Устранения сифона","Использования давления в водопроводе для сжатия воздуха, который усиливает смыв","Добавления рециркуляционного насоса"], re:"Нагнетательная ёмкость внутри бачка использует давление в магистрали для сжатия запертого воздуха, который затем выталкивает воду с дополнительной энергией для более сильного смыва."},
  {id:315, q:"Клапан-лепесток (уплотнение смывного клапана) в нижней части самотёчного бачка:", opts:["Нагревает воду","Вентилирует чашу","Снижает давление в подаче","Открывается для выпуска воды из бачка, затем снова садится, удерживая её"], re:"Подъём рычага поднимает лепесток, чтобы сбросить воду из бачка; как только бачок опорожняется, лепесток опускается и герметизирует его, чтобы бачок мог дозаполниться."},
  {id:316, q:"Калифорния требует, чтобы осевая линия унитаза находилась на каком минимальном расстоянии от боковой стены или препятствия?", opts:["15 дюймов","8 дюймов","21 дюйм","30 дюймов"], re:"Нормы требуют не менее 15 дюймов от осевой линии унитаза до любой боковой стены или препятствия, чтобы фикстурой можно было удобно пользоваться."},
  {id:317, q:"Минимальное свободное пространство, требуемое перед унитазом, составляет:", opts:["12 дюймов","6 дюймов","36 дюймов","24 дюйма"], re:"Перед унитазом должно быть обеспечено не менее 24 дюймов свободного пространства для доступа и использования."},
  {id:318, q:"Два соседних унитаза должны иметь осевые линии, разделённые не менее чем на:", opts:["15 дюймов","18 дюймов","30 дюймов","24 дюйма"], re:"Расстояние от оси до оси между двумя унитазами (или унитазом и биде) должно быть не менее 30 дюймов."},
  {id:319, q:"Слив и отвод сифона стандартного бытового унитаза должны быть не менее:", opts:["1-1/2 дюйма","2 дюйма","2-1/2 дюйма","3 дюйма"], re:"Унитаз требует слива и отвода сифона диаметром 3 дюйма для отведения стоков — больше, чем ответвления, обслуживающие раковины и ванны."},
  {id:320, q:"Минимальный размер сифона и слива для умывальника (раковины в ванной) составляет:", opts:["1-1/4 дюйма","1-1/2 дюйма","2 дюйма","3 дюйма"], re:"Умывальник может использовать сифон и слив 1-1/4 дюйма — наименьший сифон фикстуры, допускаемый нормами."},
  {id:321, q:"Минимальный размер сифона для кухонной мойки составляет:", opts:["1-1/4 дюйма","3 дюйма","2 дюйма","1-1/2 дюйма"], re:"Кухонная мойка требует сифон не менее 1-1/2 дюйма — больше, чем умывальник, так как она отводит больше и более жирные стоки."},
  {id:322, q:"Ванна обслуживается сифоном размером не менее:", opts:["1-1/4 дюйма","2 дюйма","1-1/2 дюйма","3 дюйма"], re:"Ванна использует сифон минимум 1-1/2 дюйма — тот же минимум, что и кухонная мойка."},
  {id:323, q:"Душевая кабина должна иметь минимальную чистовую внутреннюю площадь и вмещать окружность диаметром 30 дюймов размером:", opts:["1024 квадратных дюйма","576 квадратных дюймов","720 квадратных дюймов","2048 квадратных дюймов"], re:"Душ должен охватывать не менее 1024 квадратных дюймов чистовой внутренней площади и вмещать окружность диаметром 30 дюймов."},
  {id:324, q:"Слив душа и его сифон должны быть не менее:", opts:["1-1/4 дюйма","1-1/2 дюйма","2 дюйма","4 дюйма"], re:"Душ требует слив и сифон минимум 2 дюйма для отведения потока без подпора."},
  {id:325, q:"Требуемые размеры душа должны сохраняться от слива вверх до высоты не менее:", opts:["48 дюймов","60 дюймов","70 дюймов","84 дюйма"], re:"Чистовая внутренняя зона душа должна сохраняться не менее чем до 70 дюймов над сливом, при этом выступать могут только вентиль, распылитель, мыльницы и поручни."},
  {id:326, q:"Развёрнутая длина отвода сифона (от водослива сифона до вентиляции) ограничена в основном для предотвращения:", opts:["Срыва водяного затвора сифона","Замерзания воды","Высокого давления воды","Только избыточного шума"], re:"Если отвод сифона слишком длинный, перепад может сорвать затвор сифона; нормы ограничивают его длину, чтобы затвор был защищён вентиляцией."},
  {id:327, q:"Горизонтальный отвод сифона никогда не должен быть короче скольких диаметров трубы от водослива сифона до вентиляции?", opts:["Одного","Десяти","Пяти","Двух"], re:"Отвод сифона должен проходить не менее двух диаметров трубы от водослива до вентиляции, чтобы вентиляционное отверстие не оказалось ниже выпуска сифона."},
  {id:328, q:"Бытовому умывальнику обычно требуется свободное пространство перед ним не менее:", opts:["12 дюймов","30 дюймов","24 дюйма","6 дюймов"], re:"Как и унитазу, умывальнику отводится не менее 24 дюймов свободного пространства спереди, чтобы к нему можно было подойти и пользоваться им."},
  {id:329, q:"Запорные вентили подачи у раковины или унитаза устанавливаются прежде всего для того, чтобы:", opts:["Снизить давление в доме","Удерживать водяной затвор сифона","Вентилировать слив","Изолировать эту фикстуру для ремонта без отключения всего дома"], re:"Доступный угловой кран под каждой фикстурой позволяет отключить её для обслуживания, в то время как остальная часть здания продолжает получать воду."},
  {id:330, q:"Размеры черновой разводки сантехники — это расположение выводов подачи и слива, установленных:", opts:["До закрытия стен и отделки","После того как стены отделаны","Только при финальной проверке","После установки фикстур"], re:"Черновая разводка фиксирует высоту и положение выводов труб, пока стена открыта, чтобы готовые фикстуры встали в нужное место."},
  {id:331, q:"Сифон трапа в полу наиболее вероятно теряет затвор из-за:", opts:["Избыточного давления","Слишком малой вентиляции","Избыточного уклона","Испарения, когда слив используется редко"], re:"Редко используемый трап в полу может высохнуть от испарения и впустить канализационный газ — вот почему дозаторам затвора или редко используемым трапам нужно внимание."},
  {id:332, q:"Дозатор затвора сифона предусмотрен для того, чтобы:", opts:["Добавлять воду в сифон трапа для поддержания затвора","Увеличить объём смыва","Снизить давление газа","Вентилировать стояк"], re:"Дозатор затвора подаёт небольшое количество воды в сифон трапа, чтобы затвор не испарился и не впустил канализационный газ."},
  {id:333, q:"Предохранительный клапан температуры и давления (T&P) водонагревателя защищает от:", opts:["Низкого давления в подаче","Обратного потока в городскую магистраль","Избыточной температуры и давления внутри бака","Накипи от жёсткой воды"], re:"Клапан T&P открывается, если температура или давление в баке поднимаются слишком высоко, сбрасывая их до того, как бак может разорваться или взорваться."},
  {id:334, q:"Сбросная труба от предохранительного клапана T&P должна:", opts:["Быть меньше выходного отверстия клапана","Сливаться самотёком без вентиля и без сифона","Подключаться напрямую к канализации здания","Подниматься петлёй вверх к высокой точке"], re:"Сбросная линия должна быть полного сечения, идти вниз самотёком, не содержать запорного вентиля или сифона и заканчиваться в одобренной точке, чтобы всегда могла сбрасывать."},
  {id:335, q:"Сбросная труба клапана T&P должна быть того же размера, что и, или не меньше:", opts:["1/4 дюйма","Дымохода","Входа холодной воды","Выходного отверстия клапана"], re:"Сбросная труба должна быть не меньше размера выходного отверстия предохранительного клапана по всей длине, чтобы не ограничивать сбросной поток."},
  {id:336, q:"Сбросная труба T&P, оканчивающаяся внутри помещения, должна заканчиваться не выше какой высоты над полом или приёмником?", opts:["6 дюймов","2 дюйма","12 дюймов","24 дюйма"], re:"Внутренний сброс должен заканчиваться не выше 6 дюймов над полом или приёмником стоков (и не менее двух диаметров трубы), чтобы сброс был виден, но не мог ошпарить."},
  {id:337, q:"Конец сбросной трубы T&P должен:", opts:["Иметь резьбу под заглушку","Иметь вентиль для управления","Не иметь резьбового соединения","Сбрасывать вверх"], re:"Концевой выход не должен иметь резьбы, чтобы никто не мог закрыть его заглушкой, пробкой или вентилем и нарушить сбросной путь."},
  {id:338, q:"Запорный вентиль или иное сужение в сбросной линии предохранительного клапана T&P:", opts:["Требуется нормами","Допускается только снаружи","Рекомендуется для управления","Запрещено"], re:"Между предохранительным клапаном и открытым концом не допускается вентиль, тройник или переходник, поскольку любое сужение может перекрыть аварийный сброс."},
  {id:339, q:"Водонагреватель, установленный там, где протечка может причинить ущерб (например, на чердаке или верхнем этаже), требует:", opts:["Поддона со сливом, отведённым в одобренную точку","Второго предохранительного клапана","Большего дымохода","Никаких особых мер"], re:"Коррозионностойкий поддон со своим сливом в одобренную точку улавливает протечку и защищает конструкцию под нагревателем."},
  {id:340, q:"Сливная линия поддона водонагревателя должна быть не менее:", opts:["3/4 дюйма","1/2 дюйма","1-1/4 дюйма","2 дюйма"], re:"Слив поддона должен быть диаметром не менее 3/4 дюйма и идти в одобренную точку, чтобы протечка отводилась."},
  {id:341, q:"Полнопроходной запорный вентиль холодной воды на водонагревателе должен располагаться:", opts:["На выходе горячей воды","На дымоходе","На сбросной линии","На подаче холодной воды к нагревателю"], re:"На линии подачи холодной воды к нагревателю требуется полнопроходной запорный вентиль, чтобы агрегат можно было изолировать для обслуживания."},
  {id:342, q:"Почему запорный вентиль ставится на входе холодной воды, а не на выходе горячей воды водонагревателя?", opts:["Чтобы бак можно было изолировать и слить для обслуживания","Чтобы повысить температуру на выходе","Чтобы уменьшить размер дымохода","Чтобы устранить предохранительный клапан"], re:"Закрытие входа холодной воды изолирует бак от подачи, чтобы его можно было слить и обслужить; на горячей стороне тогда нет подпитки."},
  {id:343, q:"Если клапан T&P постоянно подтекает или сбрасывает, правильным действием будет:", opts:["Заглушить сбросную трубу","Заткнуть клапан","Найти и устранить причину (избыточную температуру или давление)","Снять клапан"], re:"Частый сброс сигнализирует о реальном перегреве или избыточном давлении (часто из-за теплового расширения); причину нужно устранить, а не затыкать клапан."},
  {id:344, q:"В замкнутой системе водоснабжения тепловое расширение у водонагревателя лучше всего контролировать с помощью:", opts:["Снятия предохранительного клапана","Большего дымохода","Расширительного бака на подаче холодной воды","Второго поддона"], re:"Когда обратный клапан или регулятор делают систему замкнутой, расширительный бак поглощает рост давления от нагрева, чтобы предохранительный клапан не был вынужден подтекать."},
  {id:345, q:"Предохранительный клапан T&P обычно рассчитан на открытие по температуре примерно при:", opts:["120 градусах F","150 градусах F","210 градусах F","300 градусах F"], re:"Стандартный клапан T&P настроен на сброс примерно при 210 градусах F по температуре (и обычно 150 psi по давлению), чтобы вода не вскипела в пар."},
  {id:346, q:"В Калифорнии бытовой водонагреватель должен быть раскреплён от землетрясений:", opts:["Без ремней","Одним ремнём сверху","Только одним ремнём снизу","Не менее чем двумя ремнями, в верхней и нижней третях бака"], re:"Калифорния требует крепить бак ремнями в его верхней и нижней третях, чтобы он не опрокинулся при сейсмическом сотрясении."},
  {id:347, q:"Нижний сейсмический ремень на водонагревателе должен находиться на каком минимальном расстоянии над органами управления?", opts:["4 дюйма","1 дюйм","12 дюймов","24 дюйма"], re:"Нижний ремень размещается в нижней трети, но не менее чем на 4 дюйма выше газовых органов управления, чтобы не мешать им."},
  {id:348, q:"Газовый водонагреватель, установленный в бытовом гараже, как правило, должен иметь источник зажигания (горелку), расположенный:", opts:["На уровне пола","Точно в 6 дюймах над полом","Ниже уровня пола","Не менее чем в 18 дюймах над полом, если только не сертифицирован как FVIR"], re:"В гараже горелка должна быть не менее чем в 18 дюймах над полом, чтобы более тяжёлые, чем воздух, горючие пары не достигали её, если только нагреватель не сертифицирован как устойчивый к зажиганию горючих паров (FVIR)."},
  {id:349, q:"Водонагреватель на пути транспортного средства в гараже также требует:", opts:["Более высокого дымохода","Защиты от механического удара (например, столбика или ограждения)","Большего предохранительного клапана","Второго поддона"], re:"Там, где транспортное средство может в него врезаться, нагреватель должен быть защищён ограждением или столбиком, чтобы не быть повреждённым ударом."},
  {id:350, q:"Отверстия для подачи воздуха на горение для газового водонагревателя в закрытом помещении обычно выполняются как:", opts:["Одно отверстие только на средней высоте","Без отверстий","Два отверстия, одно у верха и одно у низа помещения","Один трап в полу"], re:"Традиционный метод предусматривает два постоянных отверстия, одно в пределах 12 дюймов от верха и одно в пределах 12 дюймов от низа, чтобы воздух мог циркулировать для горения."},
  {id:351, q:"Для двух отверстий, сообщающихся напрямую с наружным воздухом, каждое отверстие должно иметь свободную площадь не менее:", opts:["1 квадратный дюйм на 1000 Btu/ч","10 квадратных дюймов на 1000 Btu/ч","1 квадратный дюйм на 100 Btu/ч","1 квадратный дюйм на 4000 Btu/ч"], re:"Когда два отверстия сообщаются напрямую с наружным воздухом (или через вертикальные каналы), каждое должно быть не менее 1 квадратного дюйма на 4000 Btu/ч суммарной мощности приборов."},
  {id:352, q:"Два требуемых отверстия для воздуха на горение должны располагаться:", opts:["Оба в пределах 12 дюймов от пола","Одно в пределах 12 дюймов от верха и одно в пределах 12 дюймов от низа","Оба у потолка","Где угодно на одной стене"], re:"Одно отверстие располагается в пределах 12 дюймов от верха помещения, а другое — в пределах 12 дюймов от низа, чтобы тёплый и холодный воздух могли обмениваться."},
  {id:353, q:"Газовый дымоход типа B, обслуживающий атмосферный водонагреватель (с прерывателем тяги), сертифицирован на зазор до горючих материалов:", opts:["0 дюймов","18 дюймов","6 дюймов","1 дюйм"], re:"Двустенный дымоход типа B сертифицирован на зазор 1 дюйм до горючего материала — намного меньше, чем требует одностенная соединительная труба."},
  {id:354, q:"Газовый дымоход (типа B) должен заканчиваться над крышей на высоте не менее:", opts:["2 футов (и согласно таблице высоты дымохода)","6 дюймов","Без минимума","Всегда 10 футов"], re:"Газовый дымоход должен выступать не менее чем на 2 фута над поверхностью крыши (и соответствовать сертифицированным требованиям зависимости высоты от расстояния) для надлежащей тяги и рассеивания."},
  {id:355, q:"Прерыватель тяги на атмосферном газовом водонагревателе служит для того, чтобы:", opts:["Повышать давление газа","Фильтровать газ","Впускать разбавляющий воздух и сбрасывать обратную тягу, чтобы горелка вентилировалась стабильно","Хранить дымовые газы"], re:"Прерыватель тяги впускает разбавляющий воздух и сбрасывает избыточную тягу, поддерживая стабильную вентиляцию горелки и предотвращая её опрокидывание тяги от перепадов давления."},
  {id:356, q:"Проточный водонагреватель (по запросу) отличается от накопительного тем, что он:", opts:["Хранит 40 галлонов горячей воды","Нагревает воду только по запросу, без накопительного бака","Не может работать на газе","Не имеет минимального расхода для запуска"], re:"Проточный агрегат нагревает воду мгновенно по мере её протекания, избегая потерь на поддержание у накопительного бака, но требуя минимального расхода для розжига."},
  {id:357, q:"По сравнению с накопительным нагревателем проточный водонагреватель прежде всего снижает:", opts:["Потери тепла на поддержание","Давление воды","Температуру дымовых газов до нуля","Необходимость в какой-либо вентиляции дымохода"], re:"Поскольку он не хранит горячую воду, проточный нагреватель устраняет потери на поддержание горячего бака, повышая КПД при малом и умеренном потреблении."},
  {id:358, q:"«Производительность в первый час» накопительного водонагревателя описывает:", opts:["Его гарантийный срок","Размер его дымохода","Толщину стенки бака","Количество галлонов горячей воды, которое он может выдать за первый час от полного состояния"], re:"Производительность в первый час — это объём горячей воды, который полностью прогретый накопительный бак может подать за один час, сочетая запасённый объём и восстановление."},
  {id:359, q:"«Скорость восстановления» водонагревателя относится к:", opts:["Тому, как быстро он может повторно нагревать воду по мере её разбора","Тому, как долго длится гарантия","Настройке предохранительного клапана","Расстоянию между ремнями"], re:"Скорость восстановления — это то, как быстро нагреватель может довести входящую холодную воду до температуры; более высокая мощность даёт более высокое восстановление."},
  {id:360, q:"Одностенная соединительная труба дымохода от водонагревателя к дымовому каналу обычно требует зазора до горючих материалов:", opts:["0 дюймов","1 дюйм","6 дюймов","Зазор не оговаривается"], re:"Одностенная соединительная труба нагревается и обычно требует 6 дюймов зазора до горючих материалов — вот почему в стеснённых местах часто применяют двустенный дымоход типа B."},
  {id:361, q:"Дымоход или соединительная труба водонагревателя должны иметь уклон:", opts:["Вниз к нагревателю","Вниз к сифону","Идеально горизонтальный","Вверх к дымоходу (обычно 1/4 дюйма на фут)"], re:"Соединительная труба должна подниматься к дымоходу, обычно не менее 1/4 дюйма на фут, чтобы горячие дымовые газы шли вверх и поддерживалась тяга."},
  {id:362, q:"Недостаток воздуха на горение для газового водонагревателя может вызвать:", opts:["Неполное сгорание и опасный угарный газ","Повышение КПД","Только понижение температуры дымовых газов","Никакого эффекта"], re:"При нехватке воздуха горелка сгорает неполно и может производить угарный газ и сажу — вот почему требуется достаточная подача воздуха на горение."},
  {id:363, q:"Водонагреватель с прямым отводом (закрытой камерой сгорания) забирает воздух на горение из:", opts:["Помещения, в котором он стоит","Наружного воздуха через выделенный воздухозабор","Предохранительного клапана","Поддона"], re:"Агрегат с прямым отводом забирает воздух на горение снаружи и отводит его наружу через закрытую систему, поэтому он не зависит от воздуха помещения."},
  {id:364, q:"Распространённый одобренный жёсткий материал для топливно-газовых трубопроводов в здании — это:", opts:["ПВХ","ABS","Чёрная (стальная) труба","Медь типа M для канализации (DWV)"], re:"Чёрная стальная труба, обычно schedule 40, является стандартным материалом для топливного газа; CSST и, где разрешено, определённая медь также используются."},
  {id:365, q:"Аббревиатура CSST означает:", opts:["Литая стальная подающая трубка","Трубка из мягкого припоя с покрытием","Гофрированная трубка из нержавеющей стали","Центральный аварийный отсечной сифон"], re:"CSST — это гофрированная трубка из нержавеющей стали, гибкое сертифицированное изделие для газовых трубопроводов, монтируемое согласно инструкциям производителя."},
  {id:366, q:"Система газовых трубопроводов из CSST должна быть электрически уравнена проводником не менее:", opts:["№ 6 AWG медный","№ 14 AWG медный","№ 18 AWG медный","Уравнивание не требуется"], re:"CSST должна быть присоединена к системе заземления электроустановки проводником не менее № 6 AWG медь, чтобы рассеивать энергию от близких молний и снижать искрение."},
  {id:367, q:"Основная причина, по которой CSST должна быть уравнена, — это:", opts:["Снижение риска искрения и пробоя от энергии молнии","Повышение давления газа","Понижение температуры дымовых газов","Ускорение потока газа"], re:"Уравнивание снижает напряжение, которое может накапливаться на тонкостенной CSST во время молнии, уменьшая вероятность пробоя дугой, который мог бы воспламенить газ."},
  {id:368, q:"Отстойник (отстойное колено) у газового прибора устанавливается для того, чтобы:", opts:["Снижать давление газа","Вентилировать газовую линию","Увеличивать расход","Улавливать грязь и влагу до того, как они достигнут органа управления прибора"], re:"Отстойник собирает мусор и конденсат, чтобы они оседали, а не загрязняли газовый клапан или жиклёр горелки прибора."},
  {id:369, q:"Отстойник чаще всего образуется из:", opts:["Обратного клапана","Регулятора давления","Только сгона","Тройника с заглушённым ниппелем на нижнем выходе"], re:"Отстойник обычно представляет собой тройник с заглушённым вертикальным ниппелем снизу, чтобы мусор падал в тупиковое колено до того, как газ повернёт к прибору."},
  {id:370, q:"Отстойник требуется на входе каких приборов?", opts:["Только газового счётчика","Водонагревателей, печей и котлов (согласно нормам)","Только уличных грилей","Никаких вообще"], re:"Отстойник требуется после запорного вентиля у приборов, таких как водонагреватели, печи и котлы; определённые приборы, например плиты, могут быть исключены."},
  {id:371, q:"Каждый газовый прибор должен иметь запорный вентиль, который:", opts:["Только на счётчике","Легко доступен и в том же помещении, рядом с прибором","За стеной","Закрыт наглухо"], re:"Запорный вентиль прибора должен находиться в том же помещении и быть легко доступным рядом с прибором, чтобы газ можно было перекрыть для обслуживания или в аварийной ситуации."},
  {id:372, q:"Гибкий соединитель газового прибора может иметь общую длину, не превышающую:", opts:["3 фута","Без ограничения","12 футов","6 футов"], re:"Сертифицированный соединитель прибора ограничен 6 футами общей длины, и на один прибор может использоваться только один соединитель."},
  {id:373, q:"Гибкий соединитель газового прибора НЕ должен:", opts:["Быть сертифицированным","Проходить через стену, пол, перегородку или быть скрытым","Подключаться к запорному вентилю","Быть цельным"], re:"Соединитель не может проходить через стены, полы, перегородки или потолки и не может быть скрыт; трубопровод здания должен доходить до того же помещения, что и прибор."},
  {id:374, q:"Соединять два гибких газовых соединителя вместе для увеличения длины:", opts:["Разрешено","Не разрешено","Требуется для плит","Допускается только снаружи"], re:"На один прибор допускается только один соединитель; соединять два вместе запрещено стандартом изделия и нормами."},
  {id:375, q:"Запорный вентиль прибора для гибкого соединителя устанавливается:", opts:["Внутри прибора","Только на счётчике","На крыше","Там, где соединитель присоединяется к жёсткому трубопроводу здания"], re:"Запорный вентиль ставится в точке, где соединитель встречается с фиксированным трубопроводом здания, чтобы до него можно было дотянуться в том же помещении, что и прибор."},
  {id:376, q:"CSST обычно НЕ разрешается:", opts:["Монтировать внутри помещений","Использовать вообще","Оставлять открытой для механического повреждения без защиты","Подключать к чёрной трубе"], re:"Там, где CSST может быть задета или истёрта, она должна быть защищена (например, накладными пластинами или гильзами), поскольку её тонкая стенка легко повреждается."},
  {id:377, q:"Чёрная стальная газовая труба соединяется с помощью:", opts:["Резьбовых соединений (или сварки) с одобренным трубным уплотнительным составом","Растворного клея","Обжимных колец","Воскового кольца"], re:"Стальная газовая труба нарезается резьбой (или сваривается) и уплотняется резьбовым составом, сертифицированным для топливного газа; растворные клеи предназначены для пластиков, а не для газа."},
  {id:378, q:"Оцинкованная стальная труба, как правило, не применяется для природного газа, потому что:", opts:["Она слишком прочная","Отслаивающийся цинк может засорять органы управления и жиклёры","Её нельзя нарезать резьбой","Она не продаётся в США"], re:"Цинковое покрытие может отслаиваться внутри трубы и застревать в клапанах и жиклёрах, поэтому для топливного газа предпочтительна чёрная сталь."},
  {id:379, q:"Подземный металлический газопровод защищается от коррозии с помощью:", opts:["Оставления его без покрытия","Заполнения его маслом","Окраски его только в белый цвет","Покрытия, обёртки или одобренной антикоррозионной защиты"], re:"Заглублённая металлическая газовая труба должна быть защищена от коррозии одобренным покрытием, обёрткой или катодными средствами, чтобы не проржаветь насквозь."},
  {id:380, q:"Соединитель прибора сертифицирован по стандарту:", opts:["ASTM D1785","ANSI Z21.24 / CSA 6.10","NEC Article 250","Только ASME B16.3"], re:"Сертифицированные газовые соединители приборов аттестованы по ANSI Z21.24/CSA 6.10, который ограничивает их 6 футами и применением на одном приборе."},
  {id:381, q:"Газовый трубопровод должен быть рассчитан на подачу:", opts:["Только самого малого прибора","Половины суммарной нагрузки","Суммарного максимального потребления всех подключённых приборов","Удвоенной мощности счётчика"], re:"Система рассчитывается на сумму максимальной мощности приборов, чтобы все они могли работать одновременно, не испытывая нехватки газа."},
  {id:382, q:"Чтобы рассчитать размер ответвления газовой трубы, нужно знать его длину и подключённую нагрузку, выраженную в:", opts:["Галлонах в минуту","Btu в час (или кубических футах в час)","Вольтах","Фунтах силы"], re:"Газовая труба рассчитывается по потреблению в Btu/ч (или cfh) и развёрнутой длине, считываемым по соответствующей расчётной таблице для данного газа и давления."},
  {id:383, q:"Для заданной длины и нагрузки увеличение допустимого падения давления в газовой линии позволяет использовать:", opts:["Трубу большего диаметра","Трубу меньшего диаметра","Никакой трубы","Только медную трубу"], re:"Допущение большего падения давления вдоль участка означает, что труба меньшего диаметра всё ещё может обеспечить требуемый расход, что отражено в расчётных таблицах."},
  {id:384, q:"По мере увеличения развёрнутой длины участка газовой трубы при той же нагрузке требуемый размер трубы:", opts:["Уменьшается","Остаётся прежним","Увеличивается","Становится нулевым"], re:"Более длинные участки теряют больше давления на трение, поэтому для переноса той же нагрузки в Btu на требуемое расстояние нужна труба большего диаметра."},
  {id:385, q:"Стандартные газовые приборы низкого давления в доме работают при давлении подачи около:", opts:["7 дюймов водяного столба","5 psi","60 psi","30 psi"], re:"Типичный бытовой природный газ подаётся при давлении примерно 7 дюймов водяного столба (около 1/4 psi); расчётные таблицы основаны на этом низком давлении."},
  {id:386, q:"Новая система газовых трубопроводов должна быть:", opts:["Заполнена водой перед использованием","Заглублена перед испытанием","Испытана давлением на герметичность перед вводом в эксплуатацию","Оставлена открытой воздуху"], re:"Газовый трубопровод испытывается давлением и подтверждается отсутствие утечек до того, как будет впущен газ и система введена в эксплуатацию."},
  {id:387, q:"Согласно Uniform/California нормам, испытание газа давлением, как правило, проводится при давлении не менее:", opts:["10 psi в течение не менее 15 минут","1 psi в течение 1 минуты","100 psi в течение 1 часа","Давление не требуется"], re:"Стандартное полевое испытание проводится при не менее 10 psi, удерживаемых не менее 15 минут (дольше — по требованию органа), без заметного падения давления."},
  {id:388, q:"Испытательное давление для газовых трубопроводов должно быть не менее скольких раз больше рабочего давления (с установленным минимумом)?", opts:["В половину","В полтора раза","В десять раз","Только равно рабочему давлению"], re:"Испытательное давление должно быть не менее 1-1/2 рабочего давления и ни в коем случае не ниже минимума по нормам, чтобы проверить соединения."},
  {id:389, q:"Во время испытания газа давлением приборы, рассчитанные на давление ниже испытательного, должны быть:", opts:["Оставлены подключёнными и открытыми","Изолированы от трубопровода (отсечены вентилем или отсоединены)","Запущены на полную мощность","Удалены из здания"], re:"Приборы, не рассчитанные на испытательное давление, изолируются закрытием их запорных вентилей или отсоединением, чтобы испытание их не повредило."},
  {id:390, q:"Испытание газа давлением считывается с помощью:", opts:["Термометра","Манометра, подходящего к данному давлению","Вольтметра","Только расходомера"], re:"Удерживаемое испытательное давление наблюдается по манометру, подходящему к диапазону, и любое заметное падение сигнализирует об утечке, которую нужно найти и устранить."},
  {id:391, q:"Отстойник обычно располагается:", opts:["Только на счётчике","После запорного вентиля прибора, близко к входу прибора","На крыше","Внутри дымохода прибора"], re:"Он размещается после запорного вентиля и как можно ближе к входу прибора, чтобы улавливать мусор непосредственно перед тем, как газ войдёт в орган управления."},
  {id:392, q:"Утечка газа проверяется на соединениях с помощью:", opts:["Открытого пламени","Одобренного раствора для обнаружения утечек (пузырьки) или сертифицированного детектора","Голых рук","Мокрой тряпки"], re:"Утечки находят с помощью некоррозионного мыльного раствора или сертифицированного газового детектора, но никогда не открытым пламенем, что было бы опасно."},
  {id:393, q:"Сейсмический (землетрясный) отсечной газовый клапан предназначен для того, чтобы:", opts:["Повышать давление газа","Автоматически прекращать подачу газа при сильном сотрясении","Заменять счётчик","Нагревать газ"], re:"Сейсмический отсечной клапан перекрывает газ при сильном движении грунта, снижая риск пожаров от газа после землетрясения."},
  {id:394, q:"Когда два прибора подключены к одной газовой линии, участок, питающий оба, должен быть рассчитан на:", opts:["Только больший прибор","Только меньший прибор","Сумму потребления обоих приборов","Половину каждого"], re:"Общий участок должен переносить суммарную нагрузку каждого прибора, который он обслуживает; только конечное ответвление к одному прибору переносит эту единичную нагрузку."},
  {id:395, q:"Система газовых трубопроводов, не прошедшая испытание давлением из-за потери давления, указывает на:", opts:["То, что труба правильного размера","Утечку, которую нужно найти и устранить до ввода в эксплуатацию","То, что газ слишком холодный","То, что счётчик слишком большой"], re:"Падение во время испытания означает утечку; её нужно локализовать и устранить, затем систему испытать повторно, прежде чем включать газ."},
  {id:396, q:"Назначение доступного запорного вентиля прибора рядом с печью или водонагревателем — это:", opts:["Повышать давление","Позволить перекрыть газ к этому прибору для обслуживания или в аварийной ситуации","Вентилировать дымоход","Рассчитывать размер трубы"], re:"Местный запорный вентиль позволяет технику или жильцу быстро изолировать именно этот прибор без отключения газа во всём здании."},
  {id:397, q:"Перед возвратом отремонтированной газовой линии в эксплуатацию сантехник должен:", opts:["Пропустить любое испытание","Повторно испытать давлением и убедиться, что оно держится, затем правильно продуть воздух","Зажечь все горелки сразу","Оставить её открытой на ночь"], re:"После ремонта линия повторно испытывается на герметичность, а затем продувается от воздуха, чтобы при повторном розжиге к горелкам поступал только газ."},
  {id:398, q:"Расчётные таблицы газовых трубопроводов используются на основе типа газа, допустимого падения давления и:", opts:["Цвета участка","Наибольшей развёрнутой длины участка","Имени монтажника","Наружной температуры"], re:"Расчёт основан на наибольшей длине участка (и подключённой нагрузке в Btu), поэтому самый требовательный путь определяет выбираемый размер трубы."},
  {id:399, q:"Отстойное колено отличается от отстойника тем, что отстойное колено в первую очередь собирает:", opts:["Электрический ток","Жидкость (конденсат), которая иначе могла бы достичь прибора","Избыточное давление","Воздух на горение"], re:"Отстойное колено даёт жидкостям нижнюю точку для сбора; на практике тот же тройник с заглушённым ниппелем также служит отстойником, улавливающим грязь и влагу."},
  {id:400, q:"Газовая линия недостаточного сечения, обслуживающая печь и водонагреватель, работающие вместе, скорее всего вызовет:", opts:["Повышение КПД","Падение давления, которое лишает горелки газа и вызывает плохое сгорание","Только понижение температуры дымовых газов","Никакого эффекта"], re:"Если общая труба слишком мала, одновременное потребление снижает давление и лишает горелки газа, вызывая слабое пламя и неполное сгорание."},
  {id:401, q:"Перекрёстное соединение лучше всего определяется как:", opts:["Стык двух питьевых водопроводных магистралей разного диаметра","Тройник, установленный на контуре рециркуляции горячей воды","Точка, где внутренний дренаж здания переходит в наружную канализацию","Любое фактическое или потенциальное соединение между системой питьевой воды и непитьевым источником"], re:"Перекрёстное соединение — это любая фактическая или потенциальная связь, через которую загрязнители могли бы попасть в питьевую воду. Контроль над ним является главной целью защиты от обратного потока."},
  {id:402, q:"Обратный поток — это нежелательное изменение направления потока в трубопроводной системе, вызванное:", opts:["Избыточной скоростью воды в магистрали","Обратным давлением или обратным сифонированием","Нормальным водоразбором на нижерасположенных приборах","Тепловым расширением воды в водонагревателе"], re:"Обратный поток возникает из-за обратного давления (давление ниже по потоку превышает давление подачи) или обратного сифонирования (отрицательное давление подачи). И то и другое может затянуть загрязнители в питьевую систему."},
  {id:403, q:"Обратное сифонирование создаётся:", opts:["Нижерасположенным насосом, толкающим воду обратно к магистрали","Отрицательным или пониженным давлением в трубопроводе подачи питьевой воды","Котлом, работающим выше уличного давления","Слишком быстрым закрытием задвижки (гидроударом)"], re:"Обратное сифонирование возникает из-за отрицательного (ниже атмосферного) давления в подаче, например при разрыве водопроводной магистрали или большом водоразборе, которое засасывает непитьевую воду в обратном направлении."},
  {id:404, q:"Обратный поток под обратным давлением возникает, когда:", opts:["Давление подачи падает ниже атмосферного","Кран остаётся открытым во время отключения магистрали","Давление в нижерасположенной системе превышает давление подачи питьевой воды","У прибора предусмотрен воздушный зазор"], re:"Обратный поток под обратным давлением происходит, когда нижерасположенный источник (насос, котёл или поднятый бак) поднимает давление выше давления подачи, заставляя поток идти в обратном направлении."},
  {id:405, q:"В контроле перекрёстных соединений соединение «высокой опасности» (с загрязнителем-контаминантом) — это такое, которое может:", opts:["Повлиять только на вкус, запах или цвет воды","Вызвать заболевание, распространить болезнь или быть смертельным при употреблении","Снизить расход на самом удалённом приборе","Увеличить счёт за воду для потребителя"], re:"Перекрёстное соединение высокой опасности (с контаминантом) связано с веществами, которые могут вызвать болезнь или смерть. Оно требует наивысшей защиты, такой как воздушный зазор или узел RP."},
  {id:406, q:"Перекрёстное соединение «низкой опасности» (с загрязнителем-поллютантом) — это такое, которое:", opts:["Может быть смертельным для потребителя","Всегда требует узла с пониженным давлением (RP)","По закону не может защищаться двойным обратным клапаном","Ухудшило бы качество воды (вкус, запах, цвет), но не угрожает здоровью"], re:"Соединение низкой опасности (с поллютантом) влияет на эстетическое качество воды, не создавая риска для здоровья. Двойной обратный клапан, как правило, является приемлемой защитой."},
  {id:407, q:"Какое устройство обеспечивает наивысшую, наиболее надёжную защиту от обратного потока?", opts:["Атмосферный вакуумный прерыватель","Узел из двух обратных клапанов","Правильно устроенный воздушный зазор","Вакуумный прерыватель на поливочном кране"], re:"Правильно подобранный физический воздушный зазор — самая надёжная защита от обратного потока, поскольку в нём нет механической части, способной выйти из строя. Он подходит для наивысших степеней опасности."},
  {id:408, q:"Требуемая степень защиты от обратного потока для конкретного соединения выбирается прежде всего на основе:", opts:["Материала трубы, используемой ниже по потоку","Степени опасности и возможного типа обратного потока","Возраста здания","Того, жилой это прибор или только коммерческий"], re:"Защита подбирается под степень опасности (низкая или высокая) и под то, возможно ли обратное давление, обратное сифонирование или и то и другое. Это определяет, какой узел приемлем."},
  {id:409, q:"Прямое перекрёстное соединение — это такое, при котором непитьевой источник может быть вытолкнут в питьевую систему за счёт:", opts:["Только обратного сифонирования","Воздушного зазора","Испарения","Обратного давления (непрерывного физического соединения под давлением)"], re:"Прямое перекрёстное соединение подвержено обратному давлению, потому что источник загрязнения физически подключён трубой к питьевой системе и может быть вытолкнут в обратном направлении под давлением."},
  {id:410, q:"Косвенное перекрёстное соединение (например, погружённый ввод, открытый в атмосферу) обычно подвержено:", opts:["Обратному сифонированию","Только обратному давлению","Только тепловому расширению","Ни обратному давлению, ни обратному сифонированию"], re:"Косвенное перекрёстное соединение (например, погружённый ввод, открытый в атмосферу) подвержено обратному сифонированию, когда давление подачи становится отрицательным."},
  {id:411, q:"Классический пример опасности перекрёстного соединения — это:", opts:["Излив крана, оканчивающийся значительно выше борта перелива","Шланг, погружённый в ведро с химикатами и подключённый к поливочному крану","Вентиляционный выпуск через крышу","Пробка прочистки в основании стояка"], re:"Садовый шланг, оставленный погружённым в загрязнитель и подключённый к поливочному крану, — хрестоматийное перекрёстное соединение, способное обратным сифонированием затянуть поллютанты в питьевую воду."},
  {id:412, q:"Программы контроля перекрёстных соединений предназначены главным образом для защиты:", opts:["Системы дренажа и вентиляции","Приборов от гидроудара","Общественной системы питьевого водоснабжения от загрязнения","Водонагревателя от накипи"], re:"Контроль перекрёстных соединений существует, чтобы не допускать загрязнителей в общественную систему питьевой воды, защищая потребителей от опасностей, передающихся через воду."},
  {id:413, q:"Изоляция всего объекта (containment) в терминологии перекрёстных соединений означает защиту от обратного потока, установленную:", opts:["У каждого отдельного прибора внутри здания","Только на стояке пожарных спринклеров","На вводе (у счётчика), чтобы отсечь весь объект целиком","Внутри водонагревателя"], re:"Изоляция объекта защищает общественную магистраль, размещая узел на вводе, так что весь объект отсекается от водопроводной подачи."},
  {id:414, q:"Локальная защита у прибора (isolation), в отличие от изоляции всего объекта, означает защиту от обратного потока:", opts:["Только на вводе на объект","В конкретной точке каждой опасности внутри объекта","На стороне водоканала от счётчика","Только у самого высокого прибора в здании"], re:"Локальная защита размещает узел у каждого внутреннего перекрёстного соединения, чтобы опасность не могла достичь других участков собственной питьевой системы здания."},
  {id:415, q:"Какое соединение в целом классифицировалось бы как ВЫСОКАЯ опасность?", opts:["Бытовая посудомоечная машина со встроенным воздушным зазором","Питьевой фонтанчик","Система газонного орошения с впрыском химикатов","Излив ванны выше борта"], re:"Система орошения, способная впрыскивать удобрения или пестициды, представляет высокую опасность (для здоровья) и требует защиты высокого уровня, например узла RP."},
  {id:416, q:"Погружённый ввод существует всякий раз, когда выпуск подачи воды:", opts:["Оканчивается выше борта перелива приёмника","Может быть затоплен так, что выпуск окажется ниже уровня жидкости, в которую он сбрасывает","Оснащён воздушным зазором","Сбрасывает в приёмник косвенного слива"], re:"Погружённый ввод — это любой выпуск подачи, который может оказаться покрыт жидкостью, которую он обслуживает, создавая перекрёстное соединение с обратным сифонированием, требующее защиты."},
  {id:417, q:"Котёл или контур водяного отопления, подключённый к питьевой подаче, является проблемой обратного потока главным образом из-за:", opts:["Обратного сифонирования при низком уличном давлении","Обратного давления плюс химической/тепловой опасности котловой воды","Только эстетических изменений вкуса","Избыточной скорости потока"], re:"Котёл работает выше давления подачи (обратное давление) и может содержать реагенты для водоподготовки, поэтому его подпиточное соединение представляет высокую опасность по обратному давлению."},
  {id:418, q:"Вспомогательный или резервный источник воды (например, частная скважина), подключённый к объекту, обслуживаемому городской водой, важен потому, что он:", opts:["Создаёт потенциальное перекрёстное соединение, способное загрязнить общественную магистраль","Всегда улучшает качество питьевой воды","Устраняет необходимость в любом устройстве защиты от обратного потока","Освобождён от правил перекрёстных соединений"], re:"Неутверждённый вспомогательный источник может дать обратный поток в общественную систему, поэтому такие объекты обычно требуют изоляции объекта на вводе."},
  {id:419, q:"Минимальный вертикальный воздушный зазор между выпуском питьевой воды и бортом перелива прибора, как правило, составляет:", opts:["1 дюйм (25 мм)","1/2 дюйма (13 мм)","2 дюйма (51 мм)","3 дюйма (76 мм)"], re:"Сантехнический кодекс устанавливает минимальный воздушный зазор в 1 дюйм. Для малых выпусков всё равно требуется этот абсолютный минимум, даже если расчётный зазор был бы меньше."},
  {id:420, q:"Как правило, минимальный воздушный зазор должен составлять не менее скольких эффективных отверстий (диаметров) выпуска подачи?", opts:["Одного","Двух","Шести","Четырёх"], re:"Воздушный зазор должен составлять не менее двух диаметров эффективного отверстия (но никогда не менее 1 дюйма), когда выпуск не находится рядом со стеной."},
  {id:421, q:"Если выпуск подачи расположен близко к одной стене, требуемый воздушный зазор увеличивается до не менее скольких эффективных отверстий?", opts:["Трёх","Двух","Четырёх","Полутора"], re:"Возле стены эффект брызг/препятствия увеличивает требование до трёх эффективных отверстий. Несколько близких стен требуют ещё большего."},
  {id:422, q:"«Эффективное отверстие», используемое для подбора воздушного зазора, — это:", opts:["Наружный диаметр трубы подачи","Минимальная площадь поперечного сечения отверстия подачи воды (его наименьший диаметр)","Длина борта перелива","Глубина приёмника"], re:"Эффективное отверстие — это наименьшее поперечное сечение выпуска. Воздушный зазор измеряется от этого отверстия вниз до борта перелива."},
  {id:423, q:"Узел защиты от обратного потока по принципу пониженного давления (RP) состоит из:", opts:["Одного обратного клапана и одного контрольного крана","Воздушного впуска, открывающегося только при атмосферном давлении","Вакуумного прерывателя и одного запорного клапана","Двух независимых обратных клапанов с дифференциальным сбросным клапаном между ними"], re:"Узел RP имеет два независимых обратных клапана и дифференциальный сбросной клапан в зоне между ними, плюс запорные клапаны и четыре контрольных крана."},
  {id:424, q:"Узел по принципу пониженного давления пригоден для защиты от:", opts:["Только обратного сифонирования, низкая опасность","Только обратного давления, низкая опасность","Ни обратного давления, ни обратного сифонирования","И обратного давления, и обратного сифонирования, включая высокую опасность"], re:"Узел RP защищает и от обратного давления, и от обратного сифонирования и допущен для высокой опасности, что делает его самым универсальным испытуемым узлом."},
  {id:425, q:"Сбросной клапан узла RP сбрасывает в атмосферу всякий раз, когда:", opts:["Давление подачи поднимается выше 80 psi","Оба обратных клапана держат плотно","Высок водоразбор ниже по потоку","Зона между обратными клапанами теряет требуемый перепад давления"], re:"Если любой из обратных клапанов пропускает и перепад на сбросном клапане падает слишком низко, сбросной клапан открывается и сбрасывает зону в атмосферу — это его отказобезопасное действие."},
  {id:426, q:"Узел RP называют «отказобезопасным в атмосферу», потому что:", opts:["Отказ обратного клапана приводит к сбросу через сбросной клапан, что сигнализирует и предотвращает обратный поток","При отказе он закрывается плотнее","При отказе он бесшумно пропускает воду","Он не требует испытаний"], re:"Отказавший обратный клапан открывает сбросной клапан, сбрасывая воду наружу, а не пропуская загрязнённую воду, — это и защита, и видимое предупреждение."},
  {id:427, q:"Узел из двух обратных клапанов (DCVA) состоит из:", opts:["Одного обратного клапана плюс атмосферного вентиля","Сбросного клапана между двумя обратными клапанами","Двух независимых подпружиненных обратных клапанов последовательно с запорными клапанами и контрольными кранами","Одного обратного клапана с вакуумным прерывателем"], re:"DCVA использует два независимых подпружиненных обратных клапана последовательно, два запорных клапана и контрольные краны — но без сбросного клапана в атмосферу."},
  {id:428, q:"Узел из двух обратных клапанов, как правило, допущен для:", opts:["Соединений высокой опасности (для здоровья)","Только обратного сифонирования","Соединений низкой опасности (поллютант), подверженных обратному давлению или обратному сифонированию","Отсутствия условий обратного потока"], re:"DCVA подходит для ситуаций низкой опасности с обратным давлением или обратным сифонированием. Он не допущен для соединений высокой опасности (с контаминантом)."},
  {id:429, q:"Ключевое физическое отличие DCVA от узла RP в том, что у RP также есть:", opts:["Второй запорный клапан","Контрольные краны","Больший вход","Дифференциальный сбросной клапан в центральной зоне"], re:"У обоих есть два обратных клапана и запорные клапаны; только RP добавляет дифференциальный сбросной клапан, который и делает его пригодным для защиты от высокой опасности."},
  {id:430, q:"Атмосферный вакуумный прерыватель (AVB) защищает от:", opts:["Только обратного давления","И обратного давления, и обратного сифонирования","Теплового расширения","Только обратного сифонирования"], re:"AVB защищает только от обратного сифонирования. Его нельзя устанавливать там, где он может подвергнуться обратному давлению."},
  {id:431, q:"Атмосферный вакуумный прерыватель должен устанавливаться так, чтобы его критический уровень был не менее чем:", opts:["На уровне борта перелива или ниже него","На 6 дюймов выше самого высокого нижерасположенного трубопровода и борта перелива","На 1 дюйм выше самого высокого нижерасположенного трубопровода и борта перелива","На 12 дюймов выше борта перелива"], re:"AVB должен располагаться не менее чем на 6 дюймов выше самого высокого нижерасположенного выпуска и борта перелива, чтобы воздушный впуск мог правильно разорвать сифон."},
  {id:432, q:"Запорный клапан, обратный клапан или другая арматура ниже атмосферного вакуумного прерывателя:", opts:["Требуются для правильной работы","Запрещены, поскольку могут удерживать давление на AVB","Рекомендуются для удобства","Допускаются, если это шаровой кран"], re:"Ниже AVB нельзя ставить никакую арматуру; любая нижерасположенная арматура могла бы подвергнуть его постоянному или обратному давлению, с которым он не справляется."},
  {id:433, q:"Атмосферный вакуумный прерыватель не рассчитан находиться под постоянным давлением воды дольше примерно:", opts:["1 часа","24 часов непрерывно без ограничений","12 часов","Любая продолжительность допустима"], re:"AVB рассчитан на периодическое использование и не должен находиться под постоянным давлением дольше примерно 12 часов, иначе его диск может залипнуть и отказать."},
  {id:434, q:"Напорный вакуумный прерыватель (PVB) отличается от AVB тем, что PVB:", opts:["Может находиться под постоянным давлением и защищает от обратного сифонирования","Не подлежит испытанию","Защищает от обратного давления","Должен устанавливаться ниже борта перелива"], re:"У PVB есть подпружиненный воздушный впуск и внутренний обратный клапан, поэтому он может оставаться под постоянным давлением. Как и AVB, он защищает только от обратного сифонирования, но не от обратного давления."},
  {id:435, q:"Узел напорного вакуумного прерывателя должен иметь критический уровень, установленный не менее чем:", opts:["На 6 дюймов выше самого высокого нижерасположенного трубопровода и борта перелива","На 12 дюймов выше самого высокого нижерасположенного трубопровода и борта перелива","На 1 дюйм выше борта перелива","На уровне самого высокого выпуска"], re:"Критический уровень PVB должен быть не менее чем на 12 дюймов выше самого высокого нижерасположенного выпуска и борта перелива — выше, чем требование для AVB."},
  {id:436, q:"Выпуски с резьбой под шланг (поливочные краны), подающие питьевую воду, должны быть защищены:", opts:["Только узлом с пониженным давлением","Двойным обратным клапаном с детектором","Несъёмным вакуумным прерывателем для поливочного крана (или эквивалентным)","Без защиты, если находятся снаружи"], re:"Шланговые выпуски требуют несъёмного вакуумного прерывателя для поливочного крана, чтобы предотвратить обратное сифонирование через подключённый шланг — очень распространённое перекрёстное соединение."},
  {id:437, q:"Вакуумный прерыватель поливочного крана должен быть «несъёмным», чтобы:", opts:["Его можно было повторно использовать на других кранах","Он увеличивал расход через шланг","Его нельзя было легко снять, лишив защиты от обратного потока","Его можно было испытывать ежегодно"], re:"Несъёмность прерывателя (со сломанным стопорным винтом) обеспечивает постоянное сохранение защиты, чтобы пользователь не мог снять её и создать опасность."},
  {id:438, q:"Какая защита от обратного потока НЕ испытывается на месте манометром и работает только за счёт физического разделения?", opts:["Воздушный зазор","Узел по принципу пониженного давления","Узел из двух обратных клапанов","Узел напорного вакуумного прерывателя"], re:"Воздушный зазор не имеет подвижных частей и проверяется измерением, а не контрольным манометром. RP, DCVA и PVB — механические узлы, испытываемые на месте."},
  {id:439, q:"Сколько контрольных кранов имеет типичный узел RP или узел из двух обратных клапанов для испытания на месте?", opts:["Один","Два","Шесть","Четыре"], re:"Эти узлы снабжены четырьмя контрольными кранами, позволяя испытателю снимать давление на каждом обратном клапане и на сбросном клапане (у RP)."},
  {id:440, q:"При испытании узла RP дифференциальный сбросной клапан должен открыться, прежде чем перепад в зоне упадёт ниже примерно:", opts:["2 psi","1 psi","10 psi","20 psi"], re:"Стандарты требуют, чтобы сбросной клапан открывался при перепаде не менее примерно 2 psi, обеспечивая сброс до того, как центральная зона потеряет своё защитное давление."},
  {id:441, q:"В узле RP центральная зона между двумя обратными клапанами поддерживается при давлении, которое:", opts:["Выше давления подачи","Равно давлению ниже по потоку","Всегда атмосферное","Ниже давления подачи, но выше атмосферного"], re:"Зона удерживается при пониженном давлении — ниже подачи, но выше атмосферного, — чтобы любая утечка через первый обратный клапан обнаруживалась и сбрасывалась."},
  {id:442, q:"Механические узлы защиты от обратного потока (RP, DCVA, PVB), как правило, должны испытываться на исправность:", opts:["Только в момент установки","Каждые десять лет","При установке и далее не реже одного раза в год (периодически)","Никогда после установки"], re:"Испытуемые узлы должны проверяться при установке и не реже одного раза в год сертифицированным испытателем, поскольку внутренние уплотнения и пружины со временем изнашиваются."},
  {id:443, q:"Узел защиты от обратного потока следует устанавливать там, где он:", opts:["Закопан прямо в грунт для защиты","Скрыт внутри отделанной стены","Погружён для предотвращения замерзания","Доступен для испытания, обслуживания и сброса через сбросной клапан"], re:"Узлы должны быть доступны для испытания и ремонта, а узел RP должен свободно сбрасывать воду; его нельзя устанавливать там, где он может быть затоплен."},
  {id:444, q:"Узел по принципу пониженного давления НЕЛЬЗЯ устанавливать:", opts:["В подземном приямке или колодце, подверженном затоплению","Над землёй в отапливаемом помещении","На горизонтальном участке с зазором под сбросным отверстием","Там, где он доступен для испытания"], re:"Поскольку его сбросной клапан сбрасывает в атмосферу, узел RP нельзя размещать в приямке, который может затопить и погрузить сбросное отверстие, лишив его защиты."},
  {id:445, q:"Воздушный впуск (вентиль) атмосферного или напорного вакуумного прерывателя работает за счёт того, что:", opts:["Открывается, впуская воздух и разрывая вакуум, когда давление подачи падает","Перекрывает подачу при высоком давлении","Непрерывно сбрасывает воду","Снижает давление ниже по потоку"], re:"Когда давление подачи падает, воздушный впуск открывается и впускает атмосферный воздух, разрывая сифон, чтобы загрязнённую воду нельзя было затянуть обратно."},
  {id:446, q:"Метод барометрической петли для защиты от обратного сифонирования основан на петле трубопровода, поднимающейся не менее чем примерно на:", opts:["10 футов","20 футов","50 футов","35 футов"], re:"Барометрическая петля должна подниматься примерно на 35 футов, чтобы атмосферное давление не могло поднять воду через петлю, предотвращая обратное сифонирование. Она не останавливает обратное давление."},
  {id:447, q:"Какой узел обычно применяется на системе пожарных спринклеров низкой опасности, где возможно обратное давление?", opts:["Атмосферный вакуумный прерыватель","Вакуумный прерыватель поливочного крана","Узел из двух обратных клапанов с детектором","Воздушный зазор"], re:"Узел из двух обратных клапанов с детектором обычен на пожарных системах низкой опасности; он останавливает обратное давление и обратное сифонирование и включает обводную линию с расходомером для обнаружения утечек."},
  {id:448, q:"Вакуумный прерыватель со сниженным разбрызгиванием (SVB) — это по сути напорный вакуумный прерыватель, который:", opts:["Защищает от обратного давления","Может устанавливаться ниже борта перелива","Минимизирует разбрызгивание воды при нормальной работе","Не требует минимальной высоты установки"], re:"SVB — это разновидность PVB, рассчитанная на ограничение разбрызгивания воды под давлением. Он по-прежнему защищает только от обратного сифонирования и требует того же приподнятого критического уровня."},
  {id:449, q:"Атмосферный вакуумный прерыватель должен устанавливаться:", opts:["Выше всех клапанов по потоку","На выходной (нижерасположенной) стороне последнего клапана, выше борта перелива","Ниже обслуживаемого прибора","В заглублённом клапанном коробе"], re:"AVB ставится на выходной стороне последнего клапана и выше борта перелива, чтобы ни один клапан не мог удерживать на нём давление и разрыв сифона был эффективным."},
  {id:450, q:"Косвенный слив от коммерческой посудомоечной машины или мойки для приготовления пищи должен сбрасываться в приёмник через:", opts:["Прямое жёсткое подключение к канализации","Узел из двух обратных клапанов на дренаже","Воздушный зазор","Вакуумный прерыватель поливочного крана на дренаже"], re:"Косвенный слив от пищевого оборудования должен сбрасываться через воздушный зазор в приёмник, чтобы стоки не могли подняться обратно в оборудование."},
  {id:451, q:"При испытании узла из двух обратных клапанов каждый обратный клапан должен удерживать минимальный статический перепад не менее:", opts:["0,5 psi","5 psi","10 psi","1 psi"], re:"Каждый обратный клапан DCVA должен удерживать не менее 1 psi в направлении потока против обратного давления, чтобы пройти испытание, доказывая, что он плотно садится."},
  {id:452, q:"Устанавливаться должен только узел защиты от обратного потока, утверждённый/сертифицированный для данного применения, то есть он был:", opts:["Окрашен в правильный цвет","Испытан и сертифицирован по признанному стандарту/лабораторией и принят органом","Изготовлен внутри страны","Установлен домовладельцем"], re:"Узлы должны быть утверждённого (сертифицированного) типа и модели, принятых уполномоченным органом, что обеспечивает их соответствие признанным эксплуатационным стандартам."},
  {id:453, q:"Главное ограничение, общее и для атмосферных, и для напорных вакуумных прерывателей, состоит в том, что они:", opts:["Не могут устанавливаться снаружи","Должны испытываться ежедневно","Не могут использоваться на системах орошения","Не защищают от обратного давления"], re:"Ни один из вакуумных прерывателей не защищает от обратного давления — они только разрывают обратное сифонирование. Там, где возможно обратное давление, требуется узел клапанного типа."},
  {id:454, q:"Контроль теплового расширения нужен в закрытой системе, потому что устройство защиты от обратного потока или обратный клапан:", opts:["Понижает температуру водонагревателя","Полностью исключает любую возможность обратного потока ниже по течению","Увеличивает расход на приборах","Не даёт нагретой воде расширяться обратно в магистраль, повышая давление"], re:"Когда обратный клапан или узел защиты от обратного потока перекрывает подачу, нагретая вода не может расшириться обратно в магистраль, поэтому для контроля растущего давления нужен расширительный бак."},
  {id:455, q:"Узел из двух обратных клапанов с детектором отличается от обычного DCVA добавлением:", opts:["Второго сбросного клапана","Атмосферного вентиля","Небольшой обводной линии с расходомером для обнаружения утечки или несанкционированного отбора","Третьего основного обратного клапана"], re:"Версия с детектором добавляет обводную линию с расходомером вокруг основных обратных клапанов, так что малые расходы (утечка или хищение) регистрируются на счётчике, что полезно на пожарных системах."},
  {id:456, q:"Узел RP, установленный снаружи над землёй, обычно всё же требует:", opts:["Установки ниже глубины промерзания в герметичном приямке","Удаления всех контрольных кранов","Защиты от замерзания и зазора для свободного сброса через сбросной клапан","Прямого закапывания в грунт"], re:"Узлу RP над землёй нужна защита от замерзания и достаточный воздушный зазор/просвет у сбросного отверстия, чтобы он мог сбрасывать воду, не будучи затопленным."},
  {id:457, q:"Сантехнический кодекс Калифорнии кодифицирован как:", opts:["Раздел (Title) 8 Свода правил Калифорнии","Раздел (Title) 16, часть 2 Свода правил Калифорнии","Раздел (Title) 25, часть 1 Свода правил Калифорнии","Раздел (Title) 24, часть 5 Свода правил Калифорнии"], re:"Сантехнический кодекс Калифорнии — это часть 5 раздела (Title) 24 (Свода строительных стандартов Калифорнии) в Своде правил Калифорнии."},
  {id:458, q:"Сантехнический кодекс Калифорнии основан (принят) на каком типовом кодексе?", opts:["Международном сантехническом кодексе (IPC)","Национальном стандартном сантехническом кодексе","Едином сантехническом кодексе (UPC), издаваемом IAPMO","Международном кодексе для жилых зданий (IRC)"], re:"Калифорния принимает Единый сантехнический кодекс (UPC), издаваемый IAPMO, с поправками штата, в качестве своего сантехнического кодекса (раздел 24, часть 5)."},
  {id:459, q:"Раздел (Title) 24 Свода правил Калифорнии в совокупности известен как:", opts:["Трудовой кодекс Калифорнии","Кодекс здравоохранения и безопасности Калифорнии","Свод строительных стандартов Калифорнии","Транспортный кодекс Калифорнии"], re:"Раздел 24 — это Свод строительных стандартов Калифорнии; его части включают строительный, сантехнический, механический, электрический и энергетический кодексы и другие."},
  {id:460, q:"Когда местная юрисдикция принимает Сантехнический кодекс Калифорнии, она может:", opts:["Принять более строгие поправки на основе местных климатических, геологических или топографических условий","Полностью отменить кодекс","Полностью игнорировать минимумы штата","Применять кодекс другого штата"], re:"Местные органы могут вносить в кодекс штата более строгие поправки, если это обосновано местными условиями, но кодекс штата задаёт базовые минимальные стандарты."},
  {id:461, q:"Согласно Закону о безопасной питьевой воде и законодательству Калифорнии «без свинца» для труб, фитингов и арматуры означает средневзвешенное содержание свинца на смачиваемых поверхностях, не превышающее:", opts:["0,25 процента","8,0 процента","2,0 процента","5,0 процента"], re:"«Без свинца» — это средневзвешенное значение не более 0,25 процента свинца по смачиваемым поверхностям труб, фитингов и арматуры, используемых для питьевой воды."},
  {id:462, q:"Для припоя и флюса, применяемых на трубопроводах питьевой воды, максимальное содержание свинца «без свинца» составляет:", opts:["0,25 процента","2,0 процента","0,2 процента","5,0 процента"], re:"Припой и флюс для питьевой воды должны содержать не более 0,2 процента свинца — более строгий показатель, чем средневзвешенные 0,25 процента для смачиваемых поверхностей."},
  {id:463, q:"Требования «без свинца» к сантехническим изделиям для питьевой воды применяются к компонентам, которые:", opts:["Транспортируют или подают воду для потребления человеком (питья или приготовления пищи)","Несут только горячую воду","Используются только в дренажных системах","Заглублены только ниже уровня земли"], re:"Правила «без свинца» охватывают изделия, транспортирующие или подающие воду для потребления человеком, включая кухонные и ванные смесители и другие питьевые устройства конечного потребления."},
  {id:464, q:"Главная заявленная цель Сантехнического кодекса Калифорнии — установить минимальные требования, защищающие:", opts:["Долю рынка производителей","Только вложения владельца здания","Эстетические дизайнерские решения","Здоровье, безопасность и благополучие населения"], re:"Как и его типовой UPC, Сантехнический кодекс Калифорнии существует для охраны здоровья, безопасности и благополучия населения через минимальные сантехнические стандарты."},
  {id:465, q:"Какой орган принимает и издаёт строительные стандарты Калифорнии, включая Сантехнический кодекс?", opts:["Агентство по охране окружающей среды США (EPA)","Совет по лицензированию подрядчиков штата (CSLB)","Федеральное сантехническое управление","Комиссия по строительным стандартам Калифорнии"], re:"Комиссия по строительным стандартам Калифорнии принимает и издаёт раздел 24, координируя ведомства штата, предлагающие сантехнические и иные стандарты."},
  {id:466, q:"Материалы и изделия, применяемые в сантехническом монтаже в Калифорнии, как правило, должны быть:", opts:["Изготовлены только в Калифорнии","Сертифицированы/утверждены по упомянутым стандартам и приняты уполномоченным органом","Самыми дешёвыми из доступных","Переработанными из прежних проектов"], re:"Изделия должны соответствовать стандартам, указанным в кодексе, и быть приемлемыми для уполномоченного органа, что обеспечивает применение проверенных материалов в системах питьевой воды и DWV."},
  {id:467, q:"Когда существует противоречие между Сантехническим кодексом Калифорнии и более строгой местной поправкой, законно принятой, монтажник должен соблюдать:", opts:["То, что менее строго","Более строгое законно принятое требование","Только каталог производителя","Правило соседней юрисдикции"], re:"Там, где законно принятая местная поправка более строгая, действует она. Кодекс задаёт минимумы, и более строгие местные правила имеют преимущество, если они правильно приняты."},
  {id:468, q:"Сантехнический кодекс Калифорнии переиздаётся по циклу принятия кодексов примерно каждые:", opts:["Год","Десять лет","Двадцать лет","Три года"], re:"Строительные стандарты Калифорнии, включая Сантехнический кодекс, как правило, издаются по трёхлетнему циклу, с промежуточными дополнениями по мере необходимости."},
  {id:469, q:"Согласно кодексу, «уполномоченный орган» (AHJ) — это:", opts:["Сантехнический склад снабжения","Ведомство или должностное лицо, ответственное за применение кодекса и утверждение монтажа","Производитель труб","Владелец объекта"], re:"AHJ — это надзорный орган или должностное лицо (обычно местный строительный департамент), которое толкует кодекс, выдаёт разрешения и принимает работы."},
  {id:470, q:"Альтернативные материалы или методы, прямо не предписанные кодексом, могут применяться только если:", opts:["Уполномоченный орган утвердит их как равноценные по качеству и безопасности","Их предпочитает подрядчик","Они дешевле вариантов, перечисленных в кодексе","Они распространены в другом штате"], re:"Кодекс допускает альтернативы, когда уполномоченный орган находит их равноценными предписанным требованиям по характеристикам, безопасности и качеству, — а не на единоличное усмотрение монтажника."},
  {id:471, q:"Трубопроводы питьевой воды в Калифорнии должны быть защищены от загрязнения, чего кодекс достигает главным образом через:", opts:["Большие диаметры труб","Контроль перекрёстных соединений и утверждённую защиту от обратного потока","Более высокое давление воды","Цветовую маркировку приборов"], re:"Положения кодекса о водоснабжении требуют контроля перекрёстных соединений и защиты от обратного потока, чтобы питьевая система оставалась свободной от загрязнения."},
  {id:472, q:"Признанный знак сторонней сертификации на изделии для питьевой воды указывает, что оно:", opts:["Освобождено от кодекса","Испытано на соответствие применимым стандартам воздействия на здоровье и эксплуатационным стандартам","Установлено лицензированным подрядчиком","Является самым дешёвым вариантом"], re:"Знак сертификации показывает, что изделие соответствует применимым стандартам (включая стандарты по содержанию свинца и воздействию на здоровье) и пригодно для использования с питьевой водой."},
  {id:473, q:"Минимальные стандарты Сантехнического кодекса Калифорнии представляют собой:", opts:["Максимум, который когда-либо разрешено устанавливать","Необязательные рекомендации без силы закона","Требования только для нового строительства","Наименее допустимый уровень работ; лучшая практика разрешена"], re:"Требования кодекса — это минимумы. Монтажник может их превышать, но не может обеспечивать меньшую защиту, чем предписывает кодекс."},
  {id:474, q:"Соблюдение Сантехнического кодекса Калифорнии юридически обязательно, потому что кодекс:", opts:["Добровольная отраслевая рекомендация","Гарантийный документ производителя","Внутренняя политика компании","Принят в закон как нормативный акт (раздел 24), исполняемый юрисдикциями"], re:"Как принятый нормативный акт штата, Сантехнический кодекс Калифорнии имеет силу закона и исполняется местными строительными инспекторами."},
  {id:475, q:"Перед началом большинства сантехнических работ подрядчик сначала должен:", opts:["Завершить работы, затем уведомить город","Получить сантехническое разрешение у уполномоченного органа","Назначить только итоговую проверку","Разместить объявление на складе снабжения"], re:"Разрешение должно быть получено до начала работ, чтобы юрисдикция могла рассмотреть объём и назначить требуемые проверки на нужных этапах."},
  {id:476, q:"Черновая (rough-in) сантехническая проверка обычно проводится:", opts:["После установки стен и отделки","После монтажа трубопроводов, но до того как они скрыты или закрыты","Только после заселения здания","До того как уложена хоть одна труба"], re:"Черновая проверка проводится, когда трубопроводы DWV, водоснабжения и газа смонтированы и ещё открыты, чтобы инспектор мог проверить работу до её сокрытия."},
  {id:477, q:"Испытание системы DWV водой требует заполнить систему водой до создания напора не менее:", opts:["5 футов","1 фута","20 футов","10 футов"], re:"Испытание DWV водой заполняет участок до напора не менее 10 футов над самым высоким фитингом этого участка, затем удерживает его для проверки на утечки."},
  {id:478, q:"При испытании DWV воздухом вместо воды кодекс, как правило, требует манометрического давления не менее:", opts:["5 psi","1 psi","20 psi","50 psi"], re:"Испытание системы DWV воздухом проводится при давлении не менее 5 psi (или 10 дюймов ртутного столба), удерживаемом без потерь в течение требуемого периода."},
  {id:479, q:"Испытание DWV (водой или воздухом) должно удерживаться без утечек минимум около:", opts:["15 минут","5 секунд","60 минут","1 минуты"], re:"Испытание DWV должно держаться не менее 15 минут без падения, доказывая, что дренажные и вентиляционные трубопроводы герметичны перед сокрытием."},
  {id:480, q:"Трубопроводы подачи (распределения) воды обычно испытываются и проверяются на герметичность испытанием воздушным давлением около:", opts:["50 psi","5 psi","10 psi","200 psi"], re:"Трубопроводы подачи питьевой воды обычно испытываются при 50 psi воздухом (или при рабочем давлении воды) и должны держать без утечек не менее 15 минут."},
  {id:481, q:"При испытании на герметичность трубопроводы распределения воды должны выдерживать испытание без утечек не менее:", opts:["5 минут","1 часа","15 минут","24 часов"], re:"Независимо от того, испытаны ли воздухом или рабочим давлением воды, трубопроводы подачи должны держать не менее 15 минут без утечек."},
  {id:482, q:"Топливные газопроводы для обычной системы низкого давления обычно проверяются на герметичность перед использованием испытанием воздухом или инертным газом не менее примерно:", opts:["10 psi","1 psi","100 psi","0,5 psi"], re:"Газопроводы низкого давления обычно испытываются при не менее 10 psi и удерживаются требуемое время; уточняйте точное значение для рабочего давления системы и редакции кодекса."},
  {id:483, q:"При испытании, требующем давления 10 psi или менее, кодекс требует манометр с ценой деления:", opts:["0,10 psi или менее","1,0 psi или менее","5 psi или менее","10 psi или менее"], re:"Испытания низкого давления (10 psi или менее) должны использовать манометр с ценой деления 0,10 psi или мельче, чтобы можно было точно обнаружить малые потери."},
  {id:484, q:"Итоговая сантехническая проверка выполняется:", opts:["До монтажа какого-либо трубопровода","Когда все сантехнические работы и приборы завершены и готовы к использованию","Только на газовой системе","Одновременно с черновой проверкой"], re:"Итоговая проверка проводится после установки приборов и завершения системы, подтверждая, что всё работает исправно и соответствует кодексу до заселения."},
  {id:485, q:"Работы, которые были закрыты или скрыты до требуемой проверки, как правило, должны быть:", opts:["Оставлены как есть и утверждены позже","Указаны только при итоговой проверке","Вскрыты или иным образом сделаны доступными для проверки по указанию инспектора","Проигнорированы, если подрядчик лицензирован"], re:"Если требуемые проверки пропущены и работы скрыты, уполномоченный орган может потребовать их вскрытия, чтобы монтаж можно было проверить."},
  {id:486, q:"Кто отвечает за уведомление органа и запрос требуемых проверок на нужных этапах?", opts:["Водоканал","Держатель разрешения (подрядчик), выполняющий работы","Производитель приборов","Владелец соседнего объекта"], re:"Держатель разрешения должен вызывать проверки на каждом требуемом этапе; работы не могут продолжаться дальше требуемой проверки, пока она не одобрена."},
  {id:487, q:"Вновь установленный узел защиты от обратного потока, смонтированный по разрешению, должен быть:", opts:["Скрыт до проверки","Установлен без какого-либо испытания","Испытан сертифицированным испытателем, а результаты предоставлены органу","Утверждён только устно"], re:"Вновь установленные испытуемые узлы должны быть испытаны сертифицированным испытателем защиты от обратного потока, а успешные результаты представлены органу для принятия."},
  {id:488, q:"Во время требуемого испытания трубопровода система должна наблюдаться так, чтобы:", opts:["Давление прикладывалось лишь на мгновение","Только после подключения приборов","Удерживать испытательное давление в течение всей требуемой продолжительности без утечек","Пока через неё активно течёт вода"], re:"Действительное испытание давлением удерживает заданное давление в течение всего требуемого времени без измеримых потерь, подтверждая, что система герметична."},
  {id:489, q:"Если проверка выявляет нарушение кодекса, подрядчик, как правило, должен:", opts:["Быстро скрыть работу","Продолжить и исправить это после заселения","Перейти на другое разрешение","Устранить недостаток и запросить повторную проверку перед продолжением"], re:"Выявленные нарушения должны быть устранены и повторно проверены; монтаж не может законно продолжаться дальше непройденной проверки, пока проблема не решена."},
  {id:490, q:"Сантехническое разрешение обычно требуется для чего из перечисленного?", opts:["Прочистки засора в существующем сифоне вантузом","Замены прокладки в смесителе","Монтажа новых трубопроводов воды, газа или DWV либо замены водонагревателя","Чистки аэратора прибора"], re:"Новые трубопроводы и значимые работы, такие как замена водонагревателя, требуют разрешения; мелкий ремонт и текущее обслуживание, как правило, не требуют."},
  {id:491, q:"Сантехническая классификация CSLB C-36 разрешает подрядчику обеспечивать:", opts:["Безопасное водоснабжение и надлежащее удаление жидких отходов в зданиях и стационарных сооружениях","Только электропроводку","Только несущий каркас","Кровлю и облицовку"], re:"Объём C-36 охватывает обеспечение безопасного, достаточного водоснабжения и надлежащего удаления жидких отходов — основу работ по питьевой воде и дренажу."},
  {id:492, q:"Что из перечисленного входит в объём работ сантехнического подрядчика C-36?", opts:["Монтаж водонагревателей, газопроводов, устройств защиты от обратного потока и систем DWV","Монтаж главного электрического щита здания","Заливка несущих фундаментов","Монтаж воздуховодов HVAC как основная специальность"], re:"C-36 охватывает системы водоснабжения и DWV, топливные газопроводы и приборы, водонагреватели и защиту от обратного потока — признанные сантехнические работы этой специальности."},
  {id:493, q:"Сантехнический подрядчик C-36, выполняющий работы, выходящие за рамки сантехнической классификации, должен:", opts:["Иметь или передать на субподряд соответствующую лицензионную классификацию для этих работ","Действовать без ограничений","Игнорировать лицензирование для попутных работ","Получить только федеральное разрешение"], re:"Работы вне объёма C-36 требуют надлежащей классификации; подрядчик не может самостоятельно выполнять смежные специальности без соответствующей лицензии."},
  {id:494, q:"Классификации подрядчиков CSLB, включая C-36, установлены согласно:", opts:["Федеральным правилам OSHA","Единому сантехническому кодексу","Разделу (Title) 24, часть 6","Своду правил Калифорнии, раздел (Title) 16 (правила Совета по лицензированию подрядчиков штата)"], re:"Классификации подрядчиков, такие как C-36, определены в разделе (Title) 16 Свода правил Калифорнии — нормативной базе CSLB."},
  {id:495, q:"Монтаж сантехническим подрядчиком C-36 медицинских газопроводов или сейсмических (срабатывающих при землетрясении) газовых отсечных клапанов:", opts:["Полностью вне объёма C-36","Закреплён исключительно за лицензией генерального инженерного подряда (A)","Разрешён только при наличии электрической лицензии","Входит в признанный объём сантехнической классификации C-36"], re:"Объём C-36 включает связанные с сантехникой работы, такие как медицинские газопроводы и сейсмические газовые отсечные клапаны, помимо систем воды, DWV и топливного газа."},
  {id:496, q:"Согласно правилам OSHA по земляным работам защитная система (откос, крепление или щит) обычно требуется для траншей глубиной:", opts:["2 фута или более","10 футов или более","5 футов или более (если только не в устойчивой скальной породе)","20 футов или более"], re:"Траншеи глубиной 5 футов или более требуют защитной системы, если только они не отрыты целиком в устойчивой скальной породе, чтобы защитить рабочих от обрушения."},
  {id:497, q:"Для выемки глубиной 20 футов или более защитная система должна быть:", opts:["Спроектирована (или основана на табличных данных, утверждённых) зарегистрированным профессиональным инженером","Выбрана любым рабочим на площадке","Опущена, поскольку слишком глубоко","Заменена только предупреждающим знаком"], re:"Выемки глубиной 20 футов или более требуют защитной системы, спроектированной зарегистрированным профессиональным инженером (или табличных данных, утверждённых инженером), из-за серьёзного риска обрушения."},
  {id:498, q:"Вынутый грунт и материалы должны держаться от края траншеи на расстоянии не менее:", opts:["2 футов","6 дюймов","10 футов","Их можно размещать у края"], re:"Отвалы грунта и техника должны быть отодвинуты не менее чем на 2 фута от края траншеи, чтобы их вес и падающий материал не вызвали обрушения."},
  {id:499, q:"Безопасный путь выхода (лестница, пандус или сходни) должен быть обеспечен в траншеях глубиной 4 фута или более, чтобы рабочим нужно было пройти не более:", opts:["10 футов по горизонтали, чтобы добраться до него","25 футов по горизонтали, чтобы добраться до него","50 футов по горизонтали, чтобы добраться до него","100 футов по горизонтали, чтобы добраться до него"], re:"В траншеях глубиной 4 фута или более путь выхода должен находиться в пределах 25 футов горизонтального перемещения для любого рабочего, обеспечивая быстрый выход."},
  {id:500, q:"Перед земляными работами сантехник должен обратиться в региональную службу единого вызова (811), чтобы:", opts:["Существующие подземные коммуникации были найдены и обозначены","Заказать трубные материалы","Назначить итоговую проверку","Получить сантехническое разрешение"], re:"Звонок в 811 перед началом копки обеспечивает обнаружение и обозначение заглублённых коммуникаций, предотвращая опасные и дорогостоящие повреждения газовых, электрических, водопроводных и других линий."}
];
